export interface GeneralData {
  projectName: string;
  section: string;
  roadType: 'ET_A' | 'B' | 'C' | 'D';
  tdpa: number;
  pvc: number;
  lanes: '1' | '2' | '3+';
  reliability: number;         // R (%)
  standardDeviation: number;   // So
  subgradeMr: number;          // MRsr (psi)
  finalServiceability: number; // Pt
  designPeriod: number;        // n (years)
  growthRate: number;          // r (%)
}

export type VehicleName = 
  | "A2" | "B2" | "B36" | "B38" | "B4" 
  | "C2" | "C36" | "C38" | "C2R2" | "C3R2"
  | "C3R3" | "C2R3" | "T2S1" | "T2S2" | "T3S2" 
  | "T3S3" | "T2S3" | "T3S1" | "T2S1R2" | "T2S1R3"
  | "T2S2R2" | "T3S1R2" | "T3S1R3" | "T3S2R2" | "T3S2R4" 
  | "T3S2R3" | "T3S3S2" | "T2S2S2" | "T3S2S2";

// The composition data is simply an array of 29 numbers (percentages)
// indexed consistently with the NOMBRES array.
export type CompositionData = number[]; 

export interface RowResult {
  no: number;
  tipo: string;
  estado: string;
  llantas: number;
  etya: number;
  b: number;
  c: number;
  d: number;
  result: number;
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { GeneralData } from '../types';
import { DEFAULT_GENERAL_DATA } from '../constants';

const GeneralDataPage: React.FC = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [isSaved, setIsSaved] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('datosGeneralesData');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Merge with defaults to ensure new fields exist if loading old data
        setFormData({ ...DEFAULT_GENERAL_DATA, ...parsed });
      } catch (e) {
        console.error("Error loading general data", e);
      }
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) : value
    }));
    setIsSaved(false);
  };

  const handleRadioChange = (name: keyof GeneralData, value: string) => {
    setFormData(prev => ({ ...prev, [name]: value }));
    setIsSaved(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    localStorage.setItem('datosGeneralesData', JSON.stringify(formData));
    setIsSaved(true);

    // Auto-hide success message
    setTimeout(() => setIsSaved(false), 3000);
  };

  const InputClass = "w-full bg-slate-900 border border-slate-700 rounded px-3 py-3 text-white focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors";
  const LabelClass = "block text-sm font-semibold text-slate-400 mb-1";

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 pb-24">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-white mb-2">Datos Generales</h1>
        <p className="text-slate-400">Parámetros fundamentales para el cálculo de ejes y diseño AASHTO.</p>
      </header>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Section 1: Project Info */}
        <div className="bg-slate-800/50 p-4 sm:p-6 rounded-xl border border-slate-700">
          <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
            <i className="fas fa-map-marked-alt text-orange-500"></i> Información del Camino
          </h3>

          <div className="grid gap-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                    <label className={LabelClass}>Nombre del Proyecto</label>
                    <input
                        type="text"
                        name="projectName"
                        value={formData.projectName}
                        onChange={handleChange}
                        className={InputClass}
                        placeholder="Ej. Carretera Federal 57"
                    />
                </div>
                <div>
                    <label className={LabelClass}>Tramo</label>
                    <input
                        type="text"
                        name="section"
                        value={formData.section}
                        onChange={handleChange}
                        className={InputClass}
                        placeholder="Ej. Km 20+000 - Km 50+000"
                    />
                </div>
            </div>

            <div>
              <label className={LabelClass}>Tipo de Camino (para cargas máximas)</label>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mt-2">
                {[
                    { val: 'ET_A', label: 'Tipo ET / A' },
                    { val: 'B', label: 'Tipo B' },
                    { val: 'C', label: 'Tipo C' },
                    { val: 'D', label: 'Tipo D' }
                ].map((opt) => (
                  <label 
                    key={opt.val} 
                    className={`cursor-pointer flex flex-col items-center justify-center p-3 rounded border transition-all active:scale-95 ${
                        formData.roadType === opt.val 
                        ? 'bg-blue-600/20 border-blue-500 text-blue-400' 
                        : 'bg-slate-900 border-slate-700 hover:bg-slate-800'
                    }`}
                  >
                    <input
                      type="radio"
                      name="roadType"
                      value={opt.val}
                      checked={formData.roadType === opt.val}
                      onChange={() => handleRadioChange('roadType', opt.val)}
                      className="hidden"
                    />
                    <span className="font-medium text-sm text-center">{opt.label}</span>
                  </label>
                ))}
              </div>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Section 2: Traffic Params */}
            <div className="bg-slate-800/50 p-4 sm:p-6 rounded-xl border border-slate-700 h-full">
                <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                    <i className="fas fa-truck-moving text-emerald-500"></i> Parámetros de Tránsito
                </h3>

                <div className="grid grid-cols-1 gap-6">
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className={LabelClass}>TDPA (Vehículos)</label>
                            <input
                                type="number"
                                name="tdpa"
                                value={formData.tdpa}
                                onChange={handleChange}
                                className={InputClass}
                                min="0"
                            />
                        </div>
                        <div>
                            <label className={LabelClass}>% Vehículos Cargados (Pvc)</label>
                            <div className="relative">
                                <input
                                    type="number"
                                    name="pvc"
                                    value={formData.pvc}
                                    onChange={handleChange}
                                    className={InputClass}
                                    min="0"
                                    max="100"
                                />
                                <span className="absolute right-4 top-3 text-slate-500">%</span>
                            </div>
                        </div>
                    </div>
                     <div className="grid grid-cols-2 gap-4">
                        <div>
                             <label className={LabelClass}>Tasa Crecimiento (r)</label>
                             <div className="relative">
                                <input
                                    type="number"
                                    name="growthRate"
                                    value={formData.growthRate}
                                    onChange={handleChange}
                                    className={InputClass}
                                    step="0.1"
                                />
                                <span className="absolute right-4 top-3 text-slate-500">%</span>
                            </div>
                        </div>
                        <div>
                             <label className={LabelClass}>Periodo Diseño (n)</label>
                             <div className="relative">
                                <input
                                    type="number"
                                    name="designPeriod"
                                    value={formData.designPeriod}
                                    onChange={handleChange}
                                    className={InputClass}
                                    min="1"
                                />
                                <span className="absolute right-4 top-3 text-slate-500">años</span>
                            </div>
                        </div>
                     </div>

                    <div>
                        <label className={LabelClass}>Número de Carriles (sentido)</label>
                        <div className="grid grid-cols-3 gap-2 mt-2">
                        {[
                            { val: '1', label: '1' },
                            { val: '2', label: '2' },
                            { val: '3+', label: '3+' }
                        ].map((opt) => (
                            <label 
                                key={opt.val}
                                className={`cursor-pointer flex items-center justify-center p-3 rounded border transition-all active:scale-95 ${
                                    formData.lanes === opt.val 
                                    ? 'bg-emerald-600/20 border-emerald-500 text-emerald-400' 
                                    : 'bg-slate-900 border-slate-700 hover:bg-slate-800'
                                }`}
                            >
                                <input
                                    type="radio"
                                    name="lanes"
                                    value={opt.val}
                                    checked={formData.lanes === opt.val}
                                    onChange={() => handleRadioChange('lanes', opt.val)}
                                    className="hidden"
                                />
                                <span className="font-medium">{opt.label}</span>
                            </label>
                        ))}
                        </div>
                    </div>
                </div>
            </div>

            {/* Section 3: Design Factors */}
            <div className="bg-slate-800/50 p-4 sm:p-6 rounded-xl border border-slate-700 h-full">
                <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                    <i className="fas fa-ruler-combined text-blue-500"></i> Factores de Diseño (AASHTO)
                </h3>

                <div className="grid grid-cols-1 gap-4">
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className={LabelClass}>Confiabilidad (R)</label>
                            <div className="relative">
                                <input
                                    type="number"
                                    name="reliability"
                                    value={formData.reliability}
                                    onChange={handleChange}
                                    className={InputClass}
                                    min="50" max="99.9" step="0.1"
                                />
                                <span className="absolute right-4 top-3 text-slate-500">%</span>
                            </div>
                        </div>
                        <div>
                            <label className={LabelClass}>Desv. Estándar (So)</label>
                            <input
                                type="number"
                                name="standardDeviation"
                                value={formData.standardDeviation}
                                onChange={handleChange}
                                className={InputClass}
                                step="0.01"
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                             <label className={LabelClass}>Serviciabilidad (Pt)</label>
                             <input
                                type="number"
                                name="finalServiceability"
                                value={formData.finalServiceability}
                                onChange={handleChange}
                                className={InputClass}
                                step="0.1"
                                min="1.5"
                                max="3.0"
                             />
                        </div>
                        <div>
                             <label className={LabelClass}>Módulo MR (Subrasante)</label>
                             <div className="relative">
                                <input
                                    type="number"
                                    name="subgradeMr"
                                    value={formData.subgradeMr}
                                    onChange={handleChange}
                                    className={InputClass}
                                    min="0"
                                />
                                <span className="absolute right-4 top-3 text-slate-500 text-xs mt-0.5">psi</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* Actions */}
        <div className="flex flex-col sm:flex-row gap-4 pt-4">
            <button
                type="submit"
                className="w-full bg-orange-600 hover:bg-orange-700 text-white font-bold py-4 px-6 rounded-lg transition-colors flex items-center justify-center gap-2 active:scale-95"
            >
                <i className="fas fa-save"></i>
                Guardar Datos
            </button>
            <button
                type="button"
                onClick={() => navigate('/composicion')}
                className="w-full bg-slate-700 hover:bg-slate-600 text-white font-bold py-4 px-6 rounded-lg transition-colors flex items-center justify-center gap-2 active:scale-95"
            >
                Siguiente <i className="fas fa-arrow-right"></i>
            </button>
        </div>

        {/* Success Feedback */}
        {isSaved && (
            <div className="fixed bottom-6 left-4 right-4 sm:left-auto sm:right-6 bg-green-500 text-white px-6 py-4 rounded-lg shadow-lg shadow-green-900/50 flex items-center justify-center gap-3 animate-bounce z-50">
                <i className="fas fa-check-circle"></i> Datos guardados
            </div>
        )}

      </form>
    </div>
  );
};

export default GeneralDataPage;

import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';

interface EsalRow {
  no: number;
  tipo: string;
  l2: number;
  lxKip: number;
  ejesAnio: number;
  fx: number;
  esalAnio: number;
}

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design (SN only here, others come from General Data)
  const [sn, setSn] = useState<number>(3.0); 

  // Data from previous steps
  const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);

  useEffect(() => {
    const savedGen = localStorage.getItem('datosGeneralesData');
    if (savedGen) setGenData({ ...DEFAULT_GENERAL_DATA, ...JSON.parse(savedGen) });

    const savedComp = localStorage.getItem('compVehData');
    if (savedComp) setCompData(JSON.parse(savedComp));
  }, []);

  // --- 1. RECALCULATE EJES (Same logic as AxlePage) ---
  const ejesResults = useMemo(() => {
    const compObj: Record<string, number> = {};
    VEHICLE_NAMES.forEach((name, idx) => {
        compObj[name] = compData[idx] || 0;
    });
    const getVal = (key: string) => compObj[key] || 0;

    const Pvc = genData.pvc;
    const TDPA = genData.tdpa;
    let fcp = 0.5;
    if (genData.lanes === '2') fcp = 0.45;
    if (genData.lanes === '3+') fcp = 0.4;
    const TDPAcd = fcp * TDPA;
    const fvp = 0.0365 * Pvc * TDPAcd;
    const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

    const formulas = [
        () => 2 * getVal("A2") * (fvp + fvv),
        () => (100 - getVal("A2") + getVal("B4")) * fvp,
        () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
        () => (2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3") + 3*getVal("T2S1R2") + 2*getVal("T2S1R3") + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + getVal("T3S2R3")) * fvp,
        () => (getVal("T2S1") + getVal("T3S1")) * fvp,
        () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38") + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3") + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1") + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2") + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3") + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")) * fvv,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
        () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
        () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
        () => (getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2") + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")) * fvp,
        () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
        () => (getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")) * fvp,
        () => (getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3") + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")) * fvv,
        () => getVal("T3S3S2") * fvp,
        () => (getVal("T3S3") + getVal("T2S3")) * fvp,
        () => getVal("T3S3S2") * fvv
    ];

    return TABLE_STATIC_ROWS.map((row, i) => formulas[i] ? formulas[i]() : 0);
  }, [genData.pvc, genData.tdpa, genData.lanes, compData]);


  // --- 2. CALCULATE ESALS ---
  const { esalRows, growthFactor } = useMemo(() => {
    const log10 = Math.log10;
    const pow = Math.pow;

    // Gt: Function of Terminal Serviceability (Now from genData)
    const pt = genData.finalServiceability;
    const Gt = log10((4.2 - pt) / 2.7);

    // Beta 18: Function of SN
    const beta18 = 0.4 + (1094 / pow(sn + 1, 5.19));

    // Calculate Growth Factor
    const r = genData.growthRate / 100;
    const n = genData.designPeriod;
    let gf = n; // Default if r is 0
    if (r !== 0) {
        gf = (pow(1 + r, n) - 1) / r;
    }

    const rows = TABLE_STATIC_ROWS.map((staticRow, index) => {
        const rowNo = staticRow[0];
        const rowTipo = staticRow[1];

        let l2 = 1;
        if (rowTipo === "Tándem") l2 = 2;
        if (rowTipo === "Trídem") l2 = 3;

        let weightTon = 0;
        switch(genData.roadType) {
            case 'ET_A': weightTon = staticRow[4]; break;
            case 'B':    weightTon = staticRow[5]; break;
            case 'C':    weightTon = staticRow[6]; break;
            case 'D':    weightTon = staticRow[7]; break;
            default:     weightTon = staticRow[4];
        }
        const lxKip = weightTon * 2.20462; 

        // Beta X
        const numeratorBx = 0.081 * pow(lxKip + l2, 3.23);
        const denominatorBx = pow(sn + 1, 5.19) * pow(l2, 3.23);
        const betaX = 0.4 + (numeratorBx / denominatorBx);

        // Fx Exponent
        const term1 = 4.79 * log10(18 + 1); 
        const term2 = 4.79 * log10(lxKip + l2);
        const term3 = 4.33 * log10(l2);
        const term4 = Gt / betaX;
        const term5 = Gt / beta18;

        const exponent = term1 - term2 + term3 + term4 - term5;
        const fx = 1 / pow(10, exponent);

        const ejes = ejesResults[index] || 0;
        const esal = fx * ejes;

        return {
            no: rowNo,
            tipo: rowTipo,
            l2,
            lxKip,
            ejesAnio: ejes,
            fx,
            esalAnio: esal
        };
    });

    return { esalRows: rows, growthFactor: gf };
  }, [sn, genData.finalServiceability, genData.roadType, genData.growthRate, genData.designPeriod, ejesResults]);

  const totalESALs1Year = useMemo(() => esalRows.reduce((acc, r) => acc + r.esalAnio, 0), [esalRows]);
  const totalESALsDesign = totalESALs1Year * growthFactor;

  const formatNum = (n: number, d: number = 2) => n.toLocaleString('en-US', { minimumFractionDigits: d, maximumFractionDigits: d });

  const exportCSV = () => {
    const headers = ["No.", "Tipo", "L2", "Lx(kip)", "Ejes 1er Año", "Fx", "ESAL 1er Año", "ESAL Diseño"];
    const rows = esalRows.map(r => [
        r.no, 
        r.tipo, 
        r.l2, 
        r.lxKip.toFixed(2), 
        Math.round(r.ejesAnio), 
        r.fx.toFixed(4), 
        r.esalAnio.toFixed(2),
        (r.esalAnio * growthFactor).toFixed(2)
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", "esals_calculo.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-24">
       <header className="mb-6">
        <h1 className="text-3xl font-bold text-white">Cálculo de ESALs</h1>
        <p className="text-slate-400">Equivalent Single Axle Load (AASHTO 93)</p>
      </header>

      {/* Configuration Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="col-span-1 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg">
            <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <i className="fas fa-cog text-blue-500"></i> Variable de Cálculo
            </h2>
            <label className="block text-sm font-semibold text-slate-400 mb-1">
                Número Estructural (SN)
            </label>
            <input 
                type="number" 
                step="0.01"
                value={sn}
                onChange={(e) => setSn(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 font-mono text-lg"
            />
             <p className="text-xs text-slate-500 mt-2">
                Modifique para recalcular Fx.
            </p>
        </div>

        <div className="col-span-1 md:col-span-2 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg flex flex-col justify-center">
            <h2 className="text-lg font-bold text-white mb-4">Datos de Diseño (Resumen)</h2>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 text-sm">
                <div className="bg-slate-900 p-3 rounded border border-slate-700">
                    <div className="text-slate-500 text-xs">Pt</div>
                    <div className="text-emerald-400 font-bold font-mono">{genData.finalServiceability}</div>
                </div>
                <div className="bg-slate-900 p-3 rounded border border-slate-700">
                     <div className="text-slate-500 text-xs">Periodo (n)</div>
                     <div className="text-white font-bold font-mono">{genData.designPeriod} años</div>
                </div>
                 <div className="bg-slate-900 p-3 rounded border border-slate-700">
