                                value={formData.finalServiceability}
                                onChange={handleChange}
                                className={InputClass}
                                step="0.1"
                                min="1.5"
                                max="3.0"
                             />
                        </div>
                        <div>
                             <label className={LabelClass}>Módulo MR (Subrasante)</label>
                             <div className="relative">
                                <input
                                    type="number"
                                    name="subgradeMr"
                                    value={formData.subgradeMr}
                                    onChange={handleChange}
                                    className={InputClass}
                                    min="0"
                                />
                                <span className="absolute right-4 top-3 text-slate-500 text-xs mt-0.5">psi</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* Section 4: Pavement Structure (New) */}
        <div className="bg-slate-800/50 p-4 sm:p-6 rounded-xl border border-slate-700">
             <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                <i className="fas fa-layer-group text-purple-500"></i> Estructuración de Capas
            </h3>

            {/* Config Row */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <div>
                    <label className={LabelClass}>Nivel de Rigidez (Valores Típicos)</label>
                    <div className="grid grid-cols-3 gap-2 mt-2">
                        {[
                            { val: 'low', label: 'Bajo' },
                            { val: 'medium', label: 'Medio' },
                            { val: 'high', label: 'Alto' }
                        ].map((opt) => (
                            <button
                                type="button"
                                key={opt.val}
                                onClick={() => handleRigidityChange(opt.val as 'low'|'medium'|'high')}
                                className={`
                                    p-3 rounded border transition-all active:scale-95 text-sm font-medium
                                    ${formData.rigidityLevel === opt.val 
                                        ? 'bg-purple-600/20 border-purple-500 text-purple-400 shadow-sm' 
                                        : 'bg-slate-900 border-slate-700 hover:bg-slate-800 text-slate-400'}
                                `}
                            >
                                {opt.label}
                            </button>
                        ))}
                    </div>
                </div>
                <div>
                    <label className={LabelClass}>Coeficiente de Drenaje (m)</label>
                    <input
                        type="number"
                        name="drainageCoefficient"
                        value={formData.drainageCoefficient || 1.0}
                        onChange={handleChange}
                        className={InputClass}
                        step="0.01"
                        min="0"
                    />
                </div>
            </div>

            {/* Dynamic Layers List */}
            <div className="space-y-4">
                <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 uppercase px-1">
                    <div className="col-span-1 text-center">#</div>
                    <div className="col-span-5 md:col-span-5">Capa</div>
                    <div className="col-span-3 md:col-span-3">Módulo (psi)</div>
                    <div className="col-span-2 md:col-span-2 text-center">a<sub>i</sub></div>
                    <div className="col-span-1"></div>
                </div>

                {formData.layers?.map((layer, index) => (
                    <div key={layer.id} className="grid grid-cols-12 gap-2 items-center bg-slate-900/50 p-2 rounded border border-slate-700/50">
                        <div className="col-span-1 text-center font-bold text-slate-400">
                            {index + 1}
                        </div>
                        <div className="col-span-11 md:col-span-5 mb-2 md:mb-0">
                            <select
                                value={layer.name}
                                onChange={(e) => handleLayerChange(layer.id, 'name', e.target.value)}
                                className={`${InputClass} py-2 text-sm`}
                            >
                                {LAYER_CATALOG.map(cat => (
                                    <option key={cat.name} value={cat.name}>{cat.name}</option>
                                ))}
                            </select>
                        </div>
                        <div className="col-span-5 md:col-span-3 pl-2 md:pl-0">
                            <input 
                                type="number" 
                                value={layer.mr}
                                onChange={(e) => handleLayerChange(layer.id, 'mr', parseFloat(e.target.value))}
                                className={`${InputClass} py-2 text-sm font-mono`}
                            />
                        </div>
                        <div className="col-span-4 md:col-span-2">
                             <input 
                                type="number" 
                                value={layer.a}
                                step="0.001"
                                onChange={(e) => handleLayerChange(layer.id, 'a', parseFloat(e.target.value))}
                                className={`${InputClass} py-2 text-sm text-center font-mono`}
                            />
                        </div>
                         <div className="col-span-3 md:col-span-1 flex justify-center">
                            {formData.layers.length > 1 && (
                                <button
                                    type="button"
                                    onClick={() => handleRemoveLayer(layer.id)}
                                    className="text-red-500 hover:text-red-400 p-2 rounded hover:bg-red-900/20"
                                    title="Eliminar capa"
                                >
                                    <i className="fas fa-trash-alt"></i>
                                </button>
                            )}
                        </div>
                    </div>
                ))}

                <button
                    type="button"
                    onClick={handleAddLayer}
                    className="w-full py-3 border-2 border-dashed border-slate-700 rounded-lg text-slate-400 hover:border-purple-500 hover:text-purple-400 hover:bg-purple-900/10 transition-colors flex items-center justify-center gap-2 font-semibold"
                >
                    <i className="fas fa-plus-circle"></i> Adicionar Capa
                </button>
            </div>
        </div>

        {/* Actions */}
        <div className="flex flex-col sm:flex-row gap-4 pt-4">
            <button
                type="submit"
                className="w-full bg-orange-600 hover:bg-orange-700 text-white font-bold py-4 px-6 rounded-lg transition-colors flex items-center justify-center gap-2 active:scale-95"
            >
                <i className="fas fa-save"></i>
                Guardar Todo
            </button>
            <button
                type="button"
                onClick={() => navigate('/composicion')}
                className="w-full bg-slate-700 hover:bg-slate-600 text-white font-bold py-4 px-6 rounded-lg transition-colors flex items-center justify-center gap-2 active:scale-95"
            >
                Siguiente <i className="fas fa-arrow-right"></i>
            </button>
        </div>

        {/* Success Feedback */}
        {isSaved && (
            <div className="fixed bottom-6 left-4 right-4 sm:left-auto sm:right-6 bg-green-500 text-white px-6 py-4 rounded-lg shadow-lg shadow-green-900/50 flex items-center justify-center gap-3 animate-bounce z-50">
                <i className="fas fa-check-circle"></i> Datos guardados
            </div>
        )}

      </form>
    </div>
  );
};

