};

export default GeneralDataPage;

import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';

interface EsalRow {
  no: number;
  tipo: string;
  l2: number;
  lxKip: number;
  ejesAnio: number;
  fx: number;
  esalAnio: number;
}

// Approximation of Inverse Standard Normal Distribution (Probit)
function inverseNormalCDF(p: number): number {
    if (p <= 0 || p >= 1) return 0;
    const t = Math.sqrt(-2 * Math.log(p < 0.5 ? p : 1 - p));
    const c0 = 2.515517;
    const c1 = 0.802853;
    const c2 = 0.010328;
    const d1 = 1.432788;
    const d2 = 0.189269;
    const d3 = 0.001308;

    const x = t - ((c2 * t + c1) * t + c0) / (((d3 * t + d2) * t + d1) * t + 1);
    return p < 0.5 ? -x : x;
}

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design (SN only here, others come from General Data)
  const [snSeed, setSnSeed] = useState<number>(3.0); 

  // Data from previous steps
  const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);

  useEffect(() => {
    const savedGen = localStorage.getItem('datosGeneralesData');
    if (savedGen) setGenData({ ...DEFAULT_GENERAL_DATA, ...JSON.parse(savedGen) });

    const savedComp = localStorage.getItem('compVehData');
    if (savedComp) setCompData(JSON.parse(savedComp));
  }, []);

  // --- 1. RECALCULATE EJES ---
  const ejesResults = useMemo(() => {
    const compObj: Record<string, number> = {};
    VEHICLE_NAMES.forEach((name, idx) => {
        compObj[name] = compData[idx] || 0;
    });
    const getVal = (key: string) => compObj[key] || 0;

    const Pvc = genData.pvc;
    const TDPA = genData.tdpa;
    let fcp = 0.5;
    if (genData.lanes === '2') fcp = 0.45;
    if (genData.lanes === '3+') fcp = 0.4;
    const TDPAcd = fcp * TDPA;
    const fvp = 0.0365 * Pvc * TDPAcd;
    const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

    const formulas = [
        () => 2 * getVal("A2") * (fvp + fvv),
        () => (100 - getVal("A2") + getVal("B4")) * fvp,
        () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
        () => (2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3") + 3*getVal("T2S1R2") + 2*getVal("T2S1R3") + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + getVal("T3S2R3")) * fvp,
        () => (getVal("T2S1") + getVal("T3S1")) * fvp,
        () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38") + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3") + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1") + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2") + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3") + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")) * fvv,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
        () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
        () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
        () => (getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2") + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")) * fvp,
        () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
        () => (getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")) * fvp,
        () => (getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3") + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")) * fvv,
        () => getVal("T3S3S2") * fvp,
        () => (getVal("T3S3") + getVal("T2S3")) * fvp,
        () => getVal("T3S3S2") * fvv
    ];

    return TABLE_STATIC_ROWS.map((row, i) => formulas[i] ? formulas[i]() : 0);
  }, [genData.pvc, genData.tdpa, genData.lanes, compData]);


  // --- 2. CALCULATE ESALS ---
  const { esalRows, growthFactor } = useMemo(() => {
    const log10 = Math.log10;
    const pow = Math.pow;

    // Gt: Function of Terminal Serviceability
    const pt = genData.finalServiceability;
    const Gt = log10((4.2 - pt) / 2.7);

    // Beta 18: Function of SN (Seed)
    const beta18 = 0.4 + (1094 / pow(snSeed + 1, 5.19));

    // Calculate Growth Factor
    const r = genData.growthRate / 100;
    const n = genData.designPeriod;
    let gf = n; 
    if (r !== 0) {
        gf = (pow(1 + r, n) - 1) / r;
    }

    const rows = TABLE_STATIC_ROWS.map((staticRow, index) => {
        const rowNo = staticRow[0];
        const rowTipo = staticRow[1];

        let l2 = 1;
        if (rowTipo === "Tándem") l2 = 2;
        if (rowTipo === "Trídem") l2 = 3;

        let weightTon = 0;
        switch(genData.roadType) {
            case 'ET_A': weightTon = staticRow[4]; break;
            case 'B':    weightTon = staticRow[5]; break;
            case 'C':    weightTon = staticRow[6]; break;
            case 'D':    weightTon = staticRow[7]; break;
            default:     weightTon = staticRow[4];
        }
        const lxKip = weightTon * 2.20462; 

        // Beta X
        const numeratorBx = 0.081 * pow(lxKip + l2, 3.23);
        const denominatorBx = pow(snSeed + 1, 5.19) * pow(l2, 3.23);
        const betaX = 0.4 + (numeratorBx / denominatorBx);

        // Fx Exponent
        const term1 = 4.79 * log10(18 + 1); 
        const term2 = 4.79 * log10(lxKip + l2);
        const term3 = 4.33 * log10(l2);
        const term4 = Gt / betaX;
        const term5 = Gt / beta18;

        const exponent = term1 - term2 + term3 + term4 - term5;
        const fx = 1 / pow(10, exponent);

        const ejes = ejesResults[index] || 0;
        const esal = fx * ejes;

        return {
            no: rowNo,
            tipo: rowTipo,
            l2,
            lxKip,
            ejesAnio: ejes,
            fx,
            esalAnio: esal
        };
    });

    return { esalRows: rows, growthFactor: gf };
  }, [snSeed, genData.finalServiceability, genData.roadType, genData.growthRate, genData.designPeriod, ejesResults]);

  const totalESALs1Year = useMemo(() => esalRows.reduce((acc, r) => acc + r.esalAnio, 0), [esalRows]);
  const totalESALsDesign = totalESALs1Year * growthFactor;

  // --- 3. HELPER: Calculate SN Required for a specific modulus ---
  const calculateAashtoSN = (Mr: number, W18: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;

    const log10 = Math.log10;
    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt;

    const termW18 = log10(W18);
    const termReliability = Zr * So;
    const termMR = 2.32 * log10(Mr);

    // This equation is solved iteratively or directly if we use the SN Seed approach
    // But since the equation depends on SN on the right side, we should strictly use 
    // the SN Seed variable from state to calculate the "Required SN" to match 
    // the traffic capacity.

    // Formula from prompt:
    // log(W18) = Zr*So + 9.36*log(SN+1) - 0.20 + [log(dPSI/2.7) / (0.4 + 1094/(SN+1)^5.19)] + 2.32*log(Mr) - 8.07

    // However, usually we solve for SN.
    // Let's use the SN Seed to calculate the Beta term, then solve for SN.
    // This assumes the SN Seed provided by user is "close enough" for the Beta term.

    const numFrac = log10(dPSI / 2.7);
    const denFrac = 0.4 + (1094 / Math.pow(snSeed + 1, 5.19));
    const termServiceability = numFrac / denFrac;

    const rhsConstant = termReliability + termMR - 8.07;
    // log(W18) = rhsConstant + 9.36*log(SN+1) - 0.20 + termServiceability
    // log(W18) - rhsConstant + 0.20 - termServiceability = 9.36 * log(SN+1)

    const lhs = termW18 - termReliability - termServiceability - termMR + 8.27; // +8.27 comes from -8.07 moved to other side? 
    // Wait, the AASHTO equation is:
    // log10(W18) = Zr*So + 9.36*log10(SN+1) - 0.20 + (...) + 2.32*log10(Mr) - 8.07
    // So:
    // 9.36*log10(SN+1) = log10(W18) - Zr*So + 0.20 - (...) - 2.32*log10(Mr) + 8.07

    const beta = termW18 - termReliability - termServiceability - termMR + 8.27;

    const snReq = -1 + Math.pow(10, beta / 9.36);
    return snReq > 0 ? snReq : 0;
  };


  // --- 4. GLOBAL SN REQUIRED (Subgrade) ---
  const snRequiredTotal = useMemo(() => {
    return calculateAashtoSN(genData.subgradeMr, totalESALsDesign);
  }, [totalESALsDesign, genData, snSeed]);


  // --- 5. LAYER STRUCTURE CALCULATION ---
  const structureLayers = useMemo(() => {
      let accumulatedSN = 0;

      return genData.layers.map((layer, index) => {
          // Identify the Supporting Layer (Layer below this one)
          // If it's the last layer, support is Subgrade.
          // Otherwise, support is the NEXT layer.
          const isLast = index === genData.layers.length - 1;
          const supportMr = isLast ? genData.subgradeMr : genData.layers[index + 1].mr;

          // Calculate SN required to protect the supporting layer
          // This is "SN1" in the prompt if we are at layer 0 protecting layer 1.
          const snRequiredForSupport = calculateAashtoSN(supportMr, totalESALsDesign);

          // Net SN needed from THIS layer = SN_Req_Support - SN_Accumulated_Above
          // In basic AASHTO, SN1 = SN_Req(Mr_Base).
          // SN2 = SN_Req(Mr_Subbase) - SN1*.
          let snNeededFromLayer = Math.max(0, snRequiredForSupport - accumulatedSN);

          // Drainage Coefficient (m)
          // Usually m=1 for asphalt (Layer 1), and user value for bases.
          // Assuming Layer 0 is asphalt.
          const m = index === 0 ? 1.0 : (genData.drainageCoefficient || 1.0);

          // h = SN / (a * m)
          const h_in = snNeededFromLayer / (layer.a * m);
          const h_cm = h_in * 2.54;

          // Round to nearest construction unit (e.g. nearest 0.5cm or 1cm?)
          // For visualization, let's keep it exact-ish but maybe show a rounded "Real"
          const h_cm_real = Math.ceil(h_cm * 2) / 2; // Round to nearest 0.5 up

          // Add ACTUAL SN provided by this layer to the accumulator for the next layer
          // Theoretically we should use the "real" thickness SN, but to keep math continuous:
          accumulatedSN += snNeededFromLayer; 

          return {
              ...layer,
              supportMr,
              snReq: snRequiredForSupport,
              m,
              h_in,
              h_cm,
              h_cm_real
          };
      });
  }, [genData.layers, genData.subgradeMr, genData.drainageCoefficient, totalESALsDesign, snSeed]);


  const formatNum = (n: number, d: number = 2) => n.toLocaleString('en-US', { minimumFractionDigits: d, maximumFractionDigits: d });

  const exportCSV = () => {
    const headers = ["No.", "Tipo", "L2", "Lx(kip)", "Ejes 1er Año", "Fx", "ESAL 1er Año", "ESAL Diseño"];
    const rows = esalRows.map(r => [
        r.no, 
        r.tipo, 
        r.l2, 
        r.lxKip.toFixed(2), 
        Math.round(r.ejesAnio), 
        r.fx.toFixed(4), 
        r.esalAnio.toFixed(2),
        (r.esalAnio * growthFactor).toFixed(2)
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", "esals_calculo.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-24">
       <header className="mb-6">
        <h1 className="text-3xl font-bold text-white">Cálculo de ESALs</h1>
        <p className="text-slate-400">Equivalent Single Axle Load (AASHTO 93)</p>
      </header>

      {/* Configuration Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="col-span-1 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg flex flex-col justify-between">
            <div>
                <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                    <i className="fas fa-calculator text-blue-500"></i> Iteración de Diseño
                </h2>

                <div className="mb-4">
                    <label className="block text-sm font-semibold text-slate-400 mb-1">
                        SN Semilla
                    </label>
                    <input 
                        type="number" 
                        step="0.01"
                        value={snSeed}
                        onChange={(e) => setSnSeed(parseFloat(e.target.value) || 0)}
                        className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 font-mono text-lg"
                    />
                </div>

                <div className="mb-2 relative p-4 bg-slate-900/50 rounded border border-slate-700">
                     <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase tracking-wider">
                        SN Requerido (Total)
                    </label>
                    <div className="text-2xl font-bold font-mono text-emerald-400">
                        {formatNum(snRequiredTotal, 2)}
                    </div>
                    {snRequiredTotal > 0 && Math.abs(snRequiredTotal - snSeed) > 0.05 && (
                        <div className="absolute right-4 top-1/2 -translate-y-1/2">
                             <button 
                                onClick={() => setSnSeed(Number(snRequiredTotal.toFixed(2)))}
                                title="Sincronizar: Usar SN Requerido como Semilla"
                                className="w-10 h-10 rounded-full bg-blue-600 hover:bg-blue-500 text-white flex items-center justify-center transition-all active:scale-95 shadow-lg shadow-blue-900/50"
                            >
                                <i className="fas fa-sync-alt"></i>
                            </button>
                        </div>
                    )}
                </div>
            </div>
             <p className="text-xs text-slate-500 mt-2 leading-relaxed">
                El diseño converge cuando <strong>SN Semilla ≈ SN Requerido</strong>.
            </p>
        </div>

        {/* REPLACED: Data Summary with Pavement Structure Visualizer */}
        <div className="col-span-1 md:col-span-2 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg">
            <h2 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <i className="fas fa-layer-group text-purple-500"></i> Estructura de Pavimento Requerida
            </h2>

            <div className="flex flex-col relative pl-4">
                {/* Headers */}
                <div className="flex items-end mb-2 text-xs font-semibold text-slate-400 uppercase tracking-wider px-2">
                    <div className="w-16 text-center">h (pulg)</div>
                    <div className="flex-1 px-4">Capa</div>
                    <div className="w-16 text-right">cm calc</div>
                    <div className="w-16 text-right">cm real</div>
                </div>

                {/* Layer Stack */}
