import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface EsalRow {
  no: number;
  tipo: string;
  l2: number;
  lxKip: number;
  ejesAnio: number;
  fx: number;
  esalAnio: number;
}

// Approximation of Inverse Standard Normal Distribution (Probit)
function inverseNormalCDF(p: number): number {
    if (p <= 0 || p >= 1) return 0;
    const t = Math.sqrt(-2 * Math.log(p < 0.5 ? p : 1 - p));
    const c0 = 2.515517;
    const c1 = 0.802853;
    const c2 = 0.010328;
    const d1 = 1.432788;
    const d2 = 0.189269;
    const d3 = 0.001308;

    const x = t - ((c2 * t + c1) * t + c0) / (((d3 * t + d2) * t + d1) * t + 1);
    return p < 0.5 ? -x : x;
}

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design
  const [snSeed, setSnSeed] = useState<number>(3.0); 

  // Store user-defined real thicknesses (keyed by layer ID)
  const [manualThicknesses, setManualThicknesses] = useState<Record<string, number>>({});

  // Data from previous steps
  const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);

  useEffect(() => {
    const savedGen = localStorage.getItem('datosGeneralesData');
    if (savedGen) setGenData({ ...DEFAULT_GENERAL_DATA, ...JSON.parse(savedGen) });

    const savedComp = localStorage.getItem('compVehData');
    if (savedComp) setCompData(JSON.parse(savedComp));
  }, []);

  // --- 1. RECALCULATE EJES ---
  const ejesResults = useMemo(() => {
    const compObj: Record<string, number> = {};
    VEHICLE_NAMES.forEach((name, idx) => {
        compObj[name] = compData[idx] || 0;
    });
    const getVal = (key: string) => compObj[key] || 0;

    const Pvc = genData.pvc;
    const TDPA = genData.tdpa;
    let fcp = 0.5;
    if (genData.lanes === '2') fcp = 0.45;
    if (genData.lanes === '3+') fcp = 0.4;
    const TDPAcd = fcp * TDPA;
    const fvp = 0.0365 * Pvc * TDPAcd;
    const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

    const formulas = [
        () => 2 * getVal("A2") * (fvp + fvv),
        () => (100 - getVal("A2") + getVal("B4")) * fvp,
        () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
        () => (2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3") + 3*getVal("T2S1R2") + 2*getVal("T2S1R3") + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + getVal("T3S2R3")) * fvp,
        () => (getVal("T2S1") + getVal("T3S1")) * fvp,
        () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38") + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3") + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1") + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2") + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3") + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")) * fvv,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
        () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
        () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
        () => (getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2") + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")) * fvp,
        () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
        () => (getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")) * fvp,
        () => (getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3") + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")) * fvv,
        () => getVal("T3S3S2") * fvp,
        () => (getVal("T3S3") + getVal("T2S3")) * fvp,
        () => getVal("T3S3S2") * fvv
    ];

    return TABLE_STATIC_ROWS.map((row, i) => formulas[i] ? formulas[i]() : 0);
  }, [genData.pvc, genData.tdpa, genData.lanes, compData]);


  // --- 2. CALCULATE ESALS ---
  const { esalRows, growthFactor } = useMemo(() => {
    const log10 = Math.log10;
    const pow = Math.pow;

    // Gt
    const pt = genData.finalServiceability;
    const Gt = log10((4.2 - pt) / 2.7);

    // Beta 18
    const beta18 = 0.4 + (1094 / pow(snSeed + 1, 5.19));

    // Growth Factor
    const r = genData.growthRate / 100;
    const n = genData.designPeriod;
    let gf = n; 
    if (r !== 0) {
        gf = (pow(1 + r, n) - 1) / r;
    }

    const rows = TABLE_STATIC_ROWS.map((staticRow, index) => {
        const rowNo = staticRow[0];
        const rowTipo = staticRow[1];

        let l2 = 1;
        if (rowTipo === "Tándem") l2 = 2;
        if (rowTipo === "Trídem") l2 = 3;

        let weightTon = 0;
        switch(genData.roadType) {
            case 'ET_A': weightTon = staticRow[4]; break;
            case 'B':    weightTon = staticRow[5]; break;
            case 'C':    weightTon = staticRow[6]; break;
            case 'D':    weightTon = staticRow[7]; break;
            default:     weightTon = staticRow[4];
        }
        const lxKip = weightTon * 2.20462; 

        // Beta X
        const numeratorBx = 0.081 * pow(lxKip + l2, 3.23);
        const denominatorBx = pow(snSeed + 1, 5.19) * pow(l2, 3.23);
        const betaX = 0.4 + (numeratorBx / denominatorBx);

        // Fx Exponent
        const term1 = 4.79 * log10(18 + 1); 
        const term2 = 4.79 * log10(lxKip + l2);
        const term3 = 4.33 * log10(l2);
        const term4 = Gt / betaX;
        const term5 = Gt / beta18;

        const exponent = term1 - term2 + term3 + term4 - term5;
        const fx = 1 / pow(10, exponent);

        const ejes = ejesResults[index] || 0;
        const esal = fx * ejes;

        return {
            no: rowNo,
            tipo: rowTipo,
            l2,
            lxKip,
            ejesAnio: ejes,
            fx,
            esalAnio: esal
        };
    });

    return { esalRows: rows, growthFactor: gf };
  }, [snSeed, genData.finalServiceability, genData.roadType, genData.growthRate, genData.designPeriod, ejesResults]);

  const totalESALs1Year = useMemo(() => esalRows.reduce((acc, r) => acc + r.esalAnio, 0), [esalRows]);
  const totalESALsDesign = totalESALs1Year * growthFactor;

  // --- 3. HELPER: Calculate SN Required ---
  const calculateAashtoSN = (Mr: number, W18: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;

    const log10 = Math.log10;
    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt;

    const termW18 = log10(W18);
    const termReliability = Zr * So;
    const termMR = 2.32 * log10(Mr);

    const numFrac = log10(dPSI / 2.7);
    const denFrac = 0.4 + (1094 / Math.pow(snSeed + 1, 5.19));
    const termServiceability = numFrac / denFrac;

    const beta = termW18 - termReliability - termServiceability - termMR + 8.27;

    const snReq = -1 + Math.pow(10, beta / 9.36);
    return snReq > 0 ? snReq : 0;
  };

  const snRequiredTotal = useMemo(() => {
    return calculateAashtoSN(genData.subgradeMr, totalESALsDesign);
  }, [totalESALsDesign, genData, snSeed]);


  // --- 5. LAYER STRUCTURE CALCULATION (Dynamic Waterfall) ---
  const structureLayers = useMemo(() => {
      let accumulatedSN = 0;

      return genData.layers.map((layer, index) => {
          // Identify Supporting Layer Mr
          const isLast = index === genData.layers.length - 1;
          const supportMr = isLast ? genData.subgradeMr : genData.layers[index + 1].mr;

          // SN Required to protect support layer
          const snRequiredForSupport = calculateAashtoSN(supportMr, totalESALsDesign);

          // Net SN needed from THIS layer
          let snNeededFromLayer = Math.max(0, snRequiredForSupport - accumulatedSN);

          // Drainage Coefficient (m) - assume 1.0 for asphalt (usually 1st layer)
          const m = index === 0 ? 1.0 : (genData.drainageCoefficient || 1.0);

          // Theoretical Thickness
          const h_in_calc = snNeededFromLayer / (layer.a * m);
          const h_cm_calc = h_in_calc * 2.54;

          // Real Thickness determination
          // 1. Check if user input exists
          // 2. Else calculate default (rounded up to 0.5)
          const manualVal = manualThicknesses[layer.id];
          const h_cm_real = manualVal !== undefined ? manualVal : Math.ceil(h_cm_calc * 2) / 2;

          // SN Actually Provided by this layer (using REAL thickness)
          // This is what we subtract from the requirements of the layer below
          const snProvided = (h_cm_real / 2.54) * layer.a * m;
          accumulatedSN += snProvided; 

          return {
              ...layer,
              supportMr,
              snReq: snRequiredForSupport,
              m,
              h_in_calc,
              h_cm_calc,
              h_cm_real,
              snProvided
          };
      });
  }, [genData.layers, genData.subgradeMr, genData.drainageCoefficient, totalESALsDesign, snSeed, manualThicknesses]);

  const handleRealThicknessChange = (layerId: string, val: string) => {
      const num = parseFloat(val);
      setManualThicknesses(prev => ({
          ...prev,
          [layerId]: isNaN(num) ? 0 : num
      }));
  };

  const formatNum = (n: number, d: number = 2) => n.toLocaleString('en-US', { minimumFractionDigits: d, maximumFractionDigits: d });

  const generatePDF = () => {
    const doc = new jsPDF();

    // --- Header ---
    doc.setFontSize(18);
    doc.text("Memoria de Cálculo - Diseño de Pavimento", 14, 20);

    doc.setFontSize(10);
    doc.text(`Proyecto: ${genData.projectName}`, 14, 30);
    doc.text(`Tramo: ${genData.section}`, 14, 35);
    doc.text(`Fecha: ${new Date().toLocaleDateString()}`, 14, 40);

    // --- 1. Datos Generales ---
    doc.setFontSize(14);
    doc.text("1. Datos de Diseño", 14, 50);

    const datosBody = [
        ["TDPA", genData.tdpa, "Confiabilidad (R)", `${genData.reliability}%`],
        ["Porcentaje de vehículos cargados", `${genData.pvc}%`, "Desviación (So)", genData.standardDeviation],
        ["Tasa Crecimiento", `${genData.growthRate}%`, "Serviciabilidad final (Pt)", genData.finalServiceability],
        ["Periodo Diseño", `${genData.designPeriod} años`, "Módulo Subrasante", `${formatNum(genData.subgradeMr, 0)} psi`],
        ["Carriles", genData.lanes, "Tipo Camino", genData.roadType],
    ];

    autoTable(doc, {
        startY: 55,
        head: [['Parámetro', 'Valor', 'Parámetro', 'Valor']],
        body: datosBody,
        theme: 'grid',
        headStyles: { fillColor: [41, 128, 185] },
    });

    // --- 2. Composición Vehicular (Resumida) ---
    // Filtramos solo los que tienen valor > 0 para ahorrar espacio
    const compRows = VEHICLE_NAMES.map((name, i) => ({ name, val: compData[i] || 0 }))
                                  .filter(item => item.val > 0)
                                  .map(item => [item.name, `${item.val}%`]);

    // Si hay muchos, los organizamos en columnas dobles o solo listamos
    let finalY = (doc as any).lastAutoTable.finalY || 60;

    doc.setFontSize(14);
    doc.text("2. Composición Vehicular ( > 0% )", 14, finalY + 10);

    // Hacemos una tabla simple
    autoTable(doc, {
        startY: finalY + 15,
        head: [['Vehículo', '%', 'Vehículo', '%']],
        body: (() => {
            const rows = [];
            for (let i = 0; i < compRows.length; i += 2) {
                const row = [
                    compRows[i][0], compRows[i][1],
                    compRows[i+1] ? compRows[i+1][0] : '', compRows[i+1] ? compRows[i+1][1] : ''
                ];
                rows.push(row);
            }
            return rows;
        })(),
        theme: 'striped',
        styles: { fontSize: 8 },
        headStyles: { fillColor: [52, 73, 94] }
    });

    finalY = (doc as any).lastAutoTable.finalY || 100;

    // --- 3. Resultados de Ejes y ESALs ---
    doc.setFontSize(14);
    doc.text("3. Cálculo de Ejes Equivalentes (ESALs)", 14, finalY + 10);

    doc.setFontSize(10);
    doc.text(`Total ESALs de Diseño: ${formatNum(totalESALsDesign, 0)}`, 14, finalY + 18);

    // Filter rows where Ejes/Año > 0
    const filteredEsalRows = esalRows.filter(r => r.ejesAnio > 0);

    autoTable(doc, {
        startY: finalY + 22,
        head: [['No', 'Tipo', 'L2', 'Lx(kip)', 'Ejes/Año', 'Fx', 'ESAL Diseño']],
        body: filteredEsalRows.map(r => [
            r.no, r.tipo, r.l2, r.lxKip.toFixed(2), 
            Math.round(r.ejesAnio).toLocaleString(),
            r.fx.toFixed(4),
            (r.esalAnio * growthFactor).toLocaleString(undefined, {maximumFractionDigits: 0})
        ]),
        theme: 'plain',
        styles: { fontSize: 7 },
        headStyles: { fillColor: [46, 204, 113], textColor: 255 }
    });

    finalY = (doc as any).lastAutoTable.finalY || 150;

    // Si falta espacio, nueva pagina
    if (finalY > 240) {
        doc.addPage();
        finalY = 20;
    }

    // --- 4. Diseño Estructural ---
    // Calculate Total SN Provided (Real)
    const totalSnReal = structureLayers.reduce((acc, layer) => acc + (layer.snProvided || 0), 0);

    doc.setFontSize(14);
    doc.text("4. Estructura de Pavimento Requerida", 14, finalY + 10);
    doc.setFontSize(10);

    // Left text
    doc.text(`SN Requerido Total: ${formatNum(snRequiredTotal, 2)}`, 14, finalY + 18);

    // Right text (SN Real Total) - Manually aligned to the right (A4 width is ~210mm, margin 14mm)
    const snRealText = `SN Real Total: ${formatNum(totalSnReal, 2)}`;
    const pageWidth = doc.internal.pageSize.getWidth();
    const textWidth = doc.getTextWidth(snRealText);
    doc.text(snRealText, pageWidth - 14 - textWidth, finalY + 18);

    autoTable(doc, {
        startY: finalY + 22,
        head: [['Capa', 'Coef (a)', 'Dren (m)', 'Mr Soporte', 'SN Req', 'h calc (cm)', 'h REAL (cm)']],
        body: structureLayers.map(l => [
            l.name,
            l.a,
            l.m,
            formatNum(l.supportMr, 0),
            formatNum(l.snReq, 2),
            formatNum(l.h_cm_calc, 2),
            l.h_cm_real.toFixed(1) // Bold logic technically not supported in simple array, but clear enough
        ]),
        theme: 'grid',
        headStyles: { fillColor: [155, 89, 182] },
        foot: [[
            { content: 'SUBRASANTE', colSpan: 3, styles: { halign: 'center', fontStyle: 'bold' } },
            { content: `Mr = ${formatNum(genData.subgradeMr, 0)} psi`, colSpan: 4 }
        ]]
    });

    doc.save("Memoria_Diseño_Pavimento.pdf");
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-24">
       <header className="mb-6">
        <h1 className="text-3xl font-bold text-white">Diseño de Pavimento</h1>
        <p className="text-slate-400">Metodología AASHTO 93 - Estructura y Espesores</p>
      </header>

      {/* Configuration Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="col-span-1 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg flex flex-col justify-between">
            <div>
                <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                    <i className="fas fa-calculator text-blue-500"></i> Iteración de Diseño
                </h2>

                <div className="mb-4">
                    <label className="block text-sm font-semibold text-slate-400 mb-1">
                        SN Semilla
                    </label>
                    <input 
                        type="number" 
                        step="0.01"
                        value={snSeed}
                        onChange={(e) => setSnSeed(parseFloat(e.target.value) || 0)}
                        className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 font-mono text-lg"
                    />
                </div>

                <div className="mb-2 relative p-4 bg-slate-900/50 rounded border border-slate-700">
                     <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase tracking-wider">
                        SN Requerido (Total)
                    </label>
                    <div className="text-2xl font-bold font-mono text-emerald-400">
                        {formatNum(snRequiredTotal, 2)}
                    </div>
                    {snRequiredTotal > 0 && Math.abs(snRequiredTotal - snSeed) > 0.05 && (
                        <div className="absolute right-4 top-1/2 -translate-y-1/2">
                             <button 
                                onClick={() => setSnSeed(Number(snRequiredTotal.toFixed(2)))}
                                title="Sincronizar: Usar SN Requerido como Semilla"
                                className="w-10 h-10 rounded-full bg-blue-600 hover:bg-blue-500 text-white flex items-center justify-center transition-all active:scale-95 shadow-lg shadow-blue-900/50"
                            >
                                <i className="fas fa-sync-alt"></i>
                            </button>
                        </div>
                    )}
                </div>
            </div>
             <p className="text-xs text-slate-500 mt-2 leading-relaxed">
                El diseño converge cuando <strong>SN Semilla ≈ SN Requerido</strong>.
            </p>
        </div>

        {/* Pavement Structure Visualizer */}
        <div className="col-span-1 md:col-span-2 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg">
            <h2 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <i className="fas fa-layer-group text-purple-500"></i> Estructura de Pavimento Requerida
            </h2>

            <div className="flex flex-col relative pl-4">
                {/* Headers */}
                <div className="flex items-end mb-2 text-xs font-semibold text-slate-400 uppercase tracking-wider px-2">
                    <div className="w-16 text-center">h (pulg)</div>
                    <div className="flex-1 px-4">Capa</div>
                    <div className="w-16 text-right">cm calc</div>
                    <div className="w-20 text-center">cm real</div>
                </div>

                {/* Layer Stack */}
                <div className="space-y-1 relative">
                    {/* Vertical line connecting layers */}
                    <div className="absolute left-0 top-0 bottom-0 w-0.5 bg-slate-700/50 -ml-2"></div>

                    {structureLayers.map((layer, idx) => {
                        // Dynamic styling based on index/type
                        let bgClass = "bg-slate-700";
                        let borderClass = "border-slate-600";
                        if (idx === 0) { bgClass = "bg-slate-900/80"; borderClass = "border-slate-600"; } // Surface
                        else if (idx === 1) { bgClass = "bg-slate-600"; borderClass = "border-slate-500"; } // Base
                        else { bgClass = "bg-amber-900/40"; borderClass = "border-amber-800/50"; } // Subbase

                        return (
                            <div key={idx} className={`relative flex items-center p-3 rounded-lg border ${bgClass} ${borderClass}`}>
                                {/* Thickness Indicator (Left - Calc Pulg) */}
                                <div className="w-16 text-center font-mono font-bold text-slate-300 text-lg">
                                    {formatNum(layer.h_in_calc, 2)}
                                </div>

                                {/* Layer Info (Center) */}
                                <div className="flex-1 px-4 border-l border-slate-600/50 mx-2 overflow-hidden">
                                    <div className="font-bold text-white text-sm md:text-base truncate">{layer.name}</div>
                                    <div className="text-xs text-slate-400 mt-1 flex flex-wrap gap-x-3">
                                        <span>a: <span className="text-emerald-400 font-mono">{layer.a}</span></span>
                                        <span>m: <span className="text-blue-400 font-mono">{layer.m}</span></span>
                                        <span>Mr: <span className="text-purple-400 font-mono">{formatNum(layer.supportMr, 0)}</span></span>
                                        <span title="SN Requerido para proteger capa inferior">SN Req: <span className="text-orange-400 font-mono">{formatNum(layer.snReq, 2)}</span></span>
                                    </div>
                                </div>

                                {/* Thickness CM Calc (Right) */}
                                <div className="w-16 text-right font-mono text-slate-400 text-sm">
                                    {formatNum(layer.h_cm_calc, 2)}
                                </div>

                                {/* Thickness CM Real Input (Far Right) */}
                                <div className="w-20 ml-2">
                                    <input 
                                        type="number" 
                                        step="0.5"
                                        min="0"
                                        value={layer.h_cm_real}
                                        onChange={(e) => handleRealThicknessChange(layer.id, e.target.value)}
                                        className="w-full bg-slate-950 border border-emerald-600/50 rounded px-1 py-1 text-center font-bold text-emerald-400 focus:outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 font-mono"
                                    />
                                </div>
                            </div>
                        );
                    })}

                    {/* Subgrade Block */}
                    <div className="relative flex items-center p-4 rounded-b-lg mt-1 border-t-2 border-dashed border-slate-600 bg-stone-900/50">
                        <div className="w-16"></div>
                        <div className="flex-1 px-4 mx-2">
                             <div className="font-bold text-stone-400 text-center uppercase tracking-widest text-sm">
                                Subrasante
                            </div>
                             <div className="text-center text-xs text-stone-600 mt-1 font-mono">
                                Mr = {formatNum(genData.subgradeMr, 0)} psi
                            </div>
                        </div>
                        <div className="w-36"></div>
                    </div>
                </div>
            </div>
        </div>
      </div>

      {/* Results Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <div className="bg-gradient-to-br from-blue-900/50 to-slate-900 border border-blue-800/50 p-6 rounded-xl flex items-center justify-between">
             <div>
                <div className="text-blue-400 text-sm font-bold uppercase tracking-wider">Total ESALs (1er Año)</div>
                <div className="text-slate-400 text-xs mt-1">Tránsito inicial</div>
             </div>
             <div className="text-2xl lg:text-3xl font-mono font-bold text-white">
                {formatNum(totalESALs1Year, 0)}
             </div>
        </div>
        <div className="bg-gradient-to-br from-emerald-900/50 to-slate-900 border border-emerald-800/50 p-6 rounded-xl flex items-center justify-between relative overflow-hidden">
             <div className="relative z-10">
                <div className="text-emerald-400 text-sm font-bold uppercase tracking-wider">Total ESALs Diseño</div>
                <div className="text-slate-400 text-xs mt-1">Acumulado ({genData.designPeriod} años)</div>
             </div>
             <div className="relative z-10 text-2xl lg:text-4xl font-mono font-bold text-white drop-shadow-lg">
                {formatNum(totalESALsDesign, 0)}
             </div>
             <div className="absolute -right-4 -bottom-4 text-emerald-500/10 text-9xl transform rotate-12">
                <i className="fas fa-road"></i>
             </div>
        </div>
      </div>

      {/* Desktop Table */}
      <div className="hidden md:block bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-xl mb-8">
        <div className="overflow-x-auto">
            <table className="w-full text-sm text-left text-slate-400">
                <thead className="text-xs text-slate-200 uppercase bg-slate-800">
                    <tr>
                        <th className="px-4 py-3 text-center">No.</th>
                        <th className="px-4 py-3">Tipo</th>
                        <th className="px-4 py-3 text-center text-blue-300">L2</th>
                        <th className="px-4 py-3 text-right text-blue-300">Lx (kip)</th>
                        <th className="px-4 py-3 text-right">Ejes 1er Año</th>
                        <th className="px-4 py-3 text-right text-emerald-400">Fx</th>
                        <th className="px-4 py-3 text-right font-bold text-slate-300">ESAL 1er Año</th>
                        <th className="px-4 py-3 text-right font-bold text-white bg-slate-700">ESAL Diseño</th>
                    </tr>
                </thead>
                <tbody>
                    {esalRows.map((row, index) => (
                        <tr key={index} className="border-b border-slate-800 hover:bg-slate-800/50 transition-colors">
                            <td className="px-4 py-3 text-center">{row.no}</td>
                            <td className="px-4 py-3 font-medium text-slate-200">{row.tipo}</td>
                            <td className="px-4 py-3 text-center text-blue-200 font-mono">{row.l2}</td>
                            <td className="px-4 py-3 text-right font-mono">{formatNum(row.lxKip)}</td>
                            <td className="px-4 py-3 text-right">{Math.round(row.ejesAnio).toLocaleString()}</td>
                            <td className="px-4 py-3 text-right font-mono text-emerald-400">{formatNum(row.fx, 4)}</td>
                            <td className="px-4 py-3 text-right font-mono text-slate-300">
                                {formatNum(row.esalAnio)}
                            </td>
                            <td className="px-4 py-3 text-right font-bold text-white bg-slate-800/30 font-mono">
                                {formatNum(row.esalAnio * growthFactor)}
                            </td>
                        </tr>
                    ))}
                    <tr className="bg-slate-800 font-bold text-white border-t-2 border-slate-600">
                        <td colSpan={7} className="px-4 py-4 text-right">TOTAL ACUMULADO:</td>
                        <td className="px-4 py-4 text-right text-lg text-emerald-400 font-mono">
                            {formatNum(totalESALsDesign)}
                        </td>
                    </tr>
                </tbody>
            </table>
        </div>
      </div>

      {/* Mobile Cards */}
      <div className="md:hidden space-y-4 mb-8">
        {esalRows.map((row) => (
            <div key={row.no} className="bg-slate-800 border border-slate-700 rounded-lg p-4 shadow-md">
                <div className="flex justify-between items-start mb-3 border-b border-slate-700 pb-2">
                    <div>
                        <span className="text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded mr-2">#{row.no}</span>
                        <span className="font-bold text-white">{row.tipo}</span>
                    </div>
                    <div className="text-right">
                        <div className="text-xs text-emerald-400 mb-0.5 font-bold">ESAL Diseño</div>
                        <div className="font-bold text-white font-mono text-lg">{formatNum(row.esalAnio * growthFactor, 0)}</div>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4 text-sm mb-3">
                    <div>
                        <span className="text-slate-500 block text-xs">Carga (Lx)</span>
                        <span className="text-slate-200 font-mono">{formatNum(row.lxKip)} kip</span>
                    </div>
                     <div>
                        <span className="text-slate-500 block text-xs">Factor (Fx)</span>
                        <span className="text-emerald-400 font-mono">{formatNum(row.fx, 4)}</span>
                    </div>
                </div>
                 <div className="bg-slate-900/50 p-2 rounded flex justify-between text-xs">
                    <span className="text-slate-500">ESAL 1er Año:</span>
                    <span className="text-slate-300 font-mono">{formatNum(row.esalAnio)}</span>
                </div>
            </div>
        ))}
      </div>

       <div className="flex flex-col sm:flex-row justify-end gap-4 fixed bottom-0 left-0 right-0 p-4 bg-slate-900/95 backdrop-blur border-t border-slate-800 z-40 md:static md:bg-transparent md:border-0 md:p-0">
            <button 
                onClick={generatePDF}
                className="flex-1 sm:flex-none bg-red-600 hover:bg-red-500 text-white px-6 py-3 rounded-lg flex items-center justify-center gap-2 font-bold shadow-lg shadow-red-900/40 transition-all active:scale-95"
            >
                <i className="fas fa-file-pdf"></i> <span className="md:inline">Memoria PDF</span>
            </button>
        </div>

    </div>
  );
};

export default EsalsPage;

import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface EsalRow {
  no: number;
  tipo: string;
  l2: number;
  lxKip: number;
  ejesAnio: number;
  fx: number;
  esalAnio: number;
}

// Approximation of Inverse Standard Normal Distribution (Probit)
function inverseNormalCDF(p: number): number {
    if (p <= 0 || p >= 1) return 0;
    const t = Math.sqrt(-2 * Math.log(p < 0.5 ? p : 1 - p));
    const c0 = 2.515517;
    const c1 = 0.802853;
    const c2 = 0.010328;
    const d1 = 1.432788;
    const d2 = 0.189269;
    const d3 = 0.001308;

    const x = t - ((c2 * t + c1) * t + c0) / (((d3 * t + d2) * t + d1) * t + 1);
    return p < 0.5 ? -x : x;
}

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design
  const [snSeed, setSnSeed] = useState<number>(3.0); 

  // Store user-defined real thicknesses (keyed by layer ID)
  const [manualThicknesses, setManualThicknesses] = useState<Record<string, number>>({});

  // Data from previous steps
  const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);

  useEffect(() => {
    const savedGen = localStorage.getItem('datosGeneralesData');
    if (savedGen) setGenData({ ...DEFAULT_GENERAL_DATA, ...JSON.parse(savedGen) });

    const savedComp = localStorage.getItem('compVehData');
    if (savedComp) setCompData(JSON.parse(savedComp));
  }, []);

  // --- 1. RECALCULATE EJES ---
  const ejesResults = useMemo(() => {
    const compObj: Record<string, number> = {};
    VEHICLE_NAMES.forEach((name, idx) => {
        compObj[name] = compData[idx] || 0;
    });
    const getVal = (key: string) => compObj[key] || 0;

    const Pvc = genData.pvc;
    const TDPA = genData.tdpa;
    let fcp = 0.5;
    if (genData.lanes === '2') fcp = 0.45;
    if (genData.lanes === '3+') fcp = 0.4;
    const TDPAcd = fcp * TDPA;
    const fvp = 0.0365 * Pvc * TDPAcd;
    const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

    const formulas = [
        () => 2 * getVal("A2") * (fvp + fvv),
        () => (100 - getVal("A2") + getVal("B4")) * fvp,
        () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
        () => (2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3") + 3*getVal("T2S1R2") + 2*getVal("T2S1R3") + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + getVal("T3S2R3")) * fvp,
        () => (getVal("T2S1") + getVal("T3S1")) * fvp,
        () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38") + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3") + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1") + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2") + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3") + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")) * fvv,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
        () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
        () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
        () => (getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2") + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")) * fvp,
        () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
        () => (getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")) * fvp,
        () => (getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3") + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")) * fvv,
        () => getVal("T3S3S2") * fvp,
        () => (getVal("T3S3") + getVal("T2S3")) * fvp,
        () => getVal("T3S3S2") * fvv
    ];

    return TABLE_STATIC_ROWS.map((row, i) => formulas[i] ? formulas[i]() : 0);
  }, [genData.pvc, genData.tdpa, genData.lanes, compData]);


  // --- 2. CALCULATE ESALS ---
  const { esalRows, growthFactor } = useMemo(() => {
    const log10 = Math.log10;
    const pow = Math.pow;

    // Gt
    const pt = genData.finalServiceability;
    const Gt = log10((4.2 - pt) / 2.7);

    // Beta 18
    const beta18 = 0.4 + (1094 / pow(snSeed + 1, 5.19));

    // Growth Factor
    const r = genData.growthRate / 100;
    const n = genData.designPeriod;
    let gf = n; 
    if (r !== 0) {
        gf = (pow(1 + r, n) - 1) / r;
    }

    const rows = TABLE_STATIC_ROWS.map((staticRow, index) => {
        const rowNo = staticRow[0];
        const rowTipo = staticRow[1];

        let l2 = 1;
        if (rowTipo === "Tándem") l2 = 2;
        if (rowTipo === "Trídem") l2 = 3;

        let weightTon = 0;
        switch(genData.roadType) {
            case 'ET_A': weightTon = staticRow[4]; break;
            case 'B':    weightTon = staticRow[5]; break;
            case 'C':    weightTon = staticRow[6]; break;
            case 'D':    weightTon = staticRow[7]; break;
            default:     weightTon = staticRow[4];
        }
        const lxKip = weightTon * 2.20462; 

        // Beta X
        const numeratorBx = 0.081 * pow(lxKip + l2, 3.23);
        const denominatorBx = pow(snSeed + 1, 5.19) * pow(l2, 3.23);
        const betaX = 0.4 + (numeratorBx / denominatorBx);

        // Fx Exponent
        const term1 = 4.79 * log10(18 + 1); 
        const term2 = 4.79 * log10(lxKip + l2);
        const term3 = 4.33 * log10(l2);
        const term4 = Gt / betaX;
        const term5 = Gt / beta18;

        const exponent = term1 - term2 + term3 + term4 - term5;
        const fx = 1 / pow(10, exponent);

        const ejes = ejesResults[index] || 0;
        const esal = fx * ejes;

        return {
            no: rowNo,
            tipo: rowTipo,
            l2,
            lxKip,
            ejesAnio: ejes,
            fx,
            esalAnio: esal
        };
    });

    return { esalRows: rows, growthFactor: gf };
  }, [snSeed, genData.finalServiceability, genData.roadType, genData.growthRate, genData.designPeriod, ejesResults]);

  const totalESALs1Year = useMemo(() => esalRows.reduce((acc, r) => acc + r.esalAnio, 0), [esalRows]);
  const totalESALsDesign = totalESALs1Year * growthFactor;

  // --- 3. HELPER: Calculate SN Required ---
  const calculateAashtoSN = (Mr: number, W18: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;

    const log10 = Math.log10;
    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt;

    const termW18 = log10(W18);
    const termReliability = Zr * So;
    const termMR = 2.32 * log10(Mr);

    const numFrac = log10(dPSI / 2.7);
    const denFrac = 0.4 + (1094 / Math.pow(snSeed + 1, 5.19));
    const termServiceability = numFrac / denFrac;

    const beta = termW18 - termReliability - termServiceability - termMR + 8.27;

    const snReq = -1 + Math.pow(10, beta / 9.36);
    return snReq > 0 ? snReq : 0;
  };

  const snRequiredTotal = useMemo(() => {
    return calculateAashtoSN(genData.subgradeMr, totalESALsDesign);
  }, [totalESALsDesign, genData, snSeed]);


  // --- 5. LAYER STRUCTURE CALCULATION (Dynamic Waterfall) ---
  const structureLayers = useMemo(() => {
      let accumulatedSN = 0;

      return genData.layers.map((layer, index) => {
          // Identify Supporting Layer Mr
          const isLast = index === genData.layers.length - 1;
          const supportMr = isLast ? genData.subgradeMr : genData.layers[index + 1].mr;

          // SN Required to protect support layer
          const snRequiredForSupport = calculateAashtoSN(supportMr, totalESALsDesign);

          // Net SN needed from THIS layer
          let snNeededFromLayer = Math.max(0, snRequiredForSupport - accumulatedSN);

          // Drainage Coefficient (m)
          // First 3 layers (index 0, 1, 2) get m=1.0. Subsequent layers use user input.
          const m = index < 3 ? 1.0 : (genData.drainageCoefficient || 1.0);

          // Theoretical Thickness
          const h_in_calc = snNeededFromLayer / (layer.a * m);
          const h_cm_calc = h_in_calc * 2.54;

          // Real Thickness determination
          // 1. Check if user input exists
          // 2. Else calculate default (rounded up to 0.5)
          const manualVal = manualThicknesses[layer.id];
          const h_cm_real = manualVal !== undefined ? manualVal : Math.ceil(h_cm_calc * 2) / 2;

          // SN Actually Provided by this layer (using REAL thickness)
          // This is what we subtract from the requirements of the layer below
          const snProvided = (h_cm_real / 2.54) * layer.a * m;
          accumulatedSN += snProvided; 

          return {
              ...layer,
              supportMr,
              snReq: snRequiredForSupport,
              m,
              h_in_calc,
              h_cm_calc,
              h_cm_real,
              snProvided
          };
      });
  }, [genData.layers, genData.subgradeMr, genData.drainageCoefficient, totalESALsDesign, snSeed, manualThicknesses]);

  const handleRealThicknessChange = (layerId: string, val: string) => {
      const num = parseFloat(val);
      setManualThicknesses(prev => ({
          ...prev,
          [layerId]: isNaN(num) ? 0 : num
      }));
  };

  const formatNum = (n: number, d: number = 2) => n.toLocaleString('en-US', { minimumFractionDigits: d, maximumFractionDigits: d });

  const generatePDF = () => {
    const doc = new jsPDF();

    // --- Header ---
    doc.setFontSize(18);
    doc.text("Memoria de Cálculo - Diseño de Pavimento", 14, 20);

    doc.setFontSize(10);
    doc.text(`Proyecto: ${genData.projectName}`, 14, 30);
    doc.text(`Tramo: ${genData.section}`, 14, 35);
    doc.text(`Fecha: ${new Date().toLocaleDateString()}`, 14, 40);

    // --- 1. Datos Generales ---
    doc.setFontSize(14);
    doc.text("1. Datos de Diseño", 14, 50);

    const datosBody = [
        ["TDPA", genData.tdpa, "Confiabilidad (R)", `${genData.reliability}%`],
        ["Porcentaje de vehículos cargados", `${genData.pvc}%`, "Desviación (So)", genData.standardDeviation],
        ["Tasa Crecimiento", `${genData.growthRate}%`, "Serviciabilidad final (Pt)", genData.finalServiceability],
        ["Periodo Diseño", `${genData.designPeriod} años`, "Módulo Subrasante", `${formatNum(genData.subgradeMr, 0)} psi`],
        ["Carriles", genData.lanes, "Tipo Camino", genData.roadType],
    ];

    autoTable(doc, {
        startY: 55,
        head: [['Parámetro', 'Valor', 'Parámetro', 'Valor']],
        body: datosBody,
        theme: 'grid',
        headStyles: { fillColor: [41, 128, 185] },
    });

    // --- 2. Composición Vehicular (Resumida) ---
    // Filtramos solo los que tienen valor > 0 para ahorrar espacio
    const compRows = VEHICLE_NAMES.map((name, i) => ({ name, val: compData[i] || 0 }))
                                  .filter(item => item.val > 0)
                                  .map(item => [item.name, `${item.val}%`]);

    // Si hay muchos, los organizamos en columnas dobles o solo listamos
    let finalY = (doc as any).lastAutoTable.finalY || 60;

    doc.setFontSize(14);
    doc.text("2. Composición Vehicular ( > 0% )", 14, finalY + 10);

    // Hacemos una tabla simple
    autoTable(doc, {
        startY: finalY + 15,
        head: [['Vehículo', '%', 'Vehículo', '%']],
        body: (() => {
            const rows = [];
            for (let i = 0; i < compRows.length; i += 2) {
                const row = [
                    compRows[i][0], compRows[i][1],
                    compRows[i+1] ? compRows[i+1][0] : '', compRows[i+1] ? compRows[i+1][1] : ''
                ];
                rows.push(row);
            }
            return rows;
        })(),
        theme: 'striped',
        styles: { fontSize: 8 },
        headStyles: { fillColor: [52, 73, 94] }
    });

    finalY = (doc as any).lastAutoTable.finalY || 100;

    // --- 3. Resultados de Ejes y ESALs ---
    doc.setFontSize(14);
    doc.text("3. Cálculo de Ejes Equivalentes (ESALs)", 14, finalY + 10);

    doc.setFontSize(10);
    doc.text(`Total ESALs de Diseño: ${formatNum(totalESALsDesign, 0)}`, 14, finalY + 18);

    // Filter rows where Ejes/Año > 0
    const filteredEsalRows = esalRows.filter(r => r.ejesAnio > 0);

    autoTable(doc, {
        startY: finalY + 22,
        head: [['No', 'Tipo', 'L2', 'Lx(kip)', 'Ejes/Año', 'Fx', 'ESAL Diseño']],
        body: filteredEsalRows.map(r => [
            r.no, r.tipo, r.l2, r.lxKip.toFixed(2), 
            Math.round(r.ejesAnio).toLocaleString(),
            r.fx.toFixed(4),
            (r.esalAnio * growthFactor).toLocaleString(undefined, {maximumFractionDigits: 0})
        ]),
        theme: 'plain',
        styles: { fontSize: 7 },
        headStyles: { fillColor: [46, 204, 113], textColor: 255 }
    });

    finalY = (doc as any).lastAutoTable.finalY || 150;

    // Si falta espacio, nueva pagina
    if (finalY > 240) {
        doc.addPage();
        finalY = 20;
    }

    // --- 4. Diseño Estructural ---
    // Calculate Total SN Provided (Real)
    const totalSnReal = structureLayers.reduce((acc, layer) => acc + (layer.snProvided || 0), 0);

    doc.setFontSize(14);
    doc.text("4. Estructura de Pavimento Requerida", 14, finalY + 10);
    doc.setFontSize(10);

    // Left text
    doc.text(`SN Requerido Total: ${formatNum(snRequiredTotal, 2)}`, 14, finalY + 18);

    // Right text (SN Real Total) - Manually aligned to the right (A4 width is ~210mm, margin 14mm)
    const snRealText = `SN Real Total: ${formatNum(totalSnReal, 2)}`;
    const pageWidth = doc.internal.pageSize.getWidth();
    const textWidth = doc.getTextWidth(snRealText);
    doc.text(snRealText, pageWidth - 14 - textWidth, finalY + 18);

    autoTable(doc, {
        startY: finalY + 22,
        head: [['Capa', 'Coef (a)', 'Dren (m)', 'Mr Soporte', 'SN Req', 'h calc (cm)', 'h REAL (cm)']],
        body: structureLayers.map(l => [
            l.name,
            l.a,
            l.m,
            formatNum(l.supportMr, 0),
            formatNum(l.snReq, 2),
            formatNum(l.h_cm_calc, 2),
            l.h_cm_real.toFixed(1) // Bold logic technically not supported in simple array, but clear enough
        ]),
        theme: 'grid',
        headStyles: { fillColor: [155, 89, 182] },
        foot: [[
            { content: 'SUBRASANTE', colSpan: 3, styles: { halign: 'center', fontStyle: 'bold' } },
            { content: `Mr = ${formatNum(genData.subgradeMr, 0)} psi`, colSpan: 4 }
        ]]
    });

    doc.save("Memoria_Diseño_Pavimento.pdf");
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-24">
       <header className="mb-6">
        <h1 className="text-3xl font-bold text-white">Diseño de Pavimento</h1>
        <p className="text-slate-400">Metodología AASHTO 93 - Estructura y Espesores</p>
      </header>

      {/* Configuration Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="col-span-1 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg flex flex-col justify-between">
            <div>
                <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                    <i className="fas fa-calculator text-blue-500"></i> Iteración de Diseño
                </h2>

                <div className="mb-4">
                    <label className="block text-sm font-semibold text-slate-400 mb-1">
                        SN Semilla
                    </label>
                    <input 
                        type="number" 
                        step="0.01"
                        value={snSeed}
                        onChange={(e) => setSnSeed(parseFloat(e.target.value) || 0)}
                        className="w-full bg-slate-900 border border-slate-600 rounded px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 font-mono text-lg"
                    />
                </div>

                <div className="mb-2 relative p-4 bg-slate-900/50 rounded border border-slate-700">
                     <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase tracking-wider">
                        SN Requerido (Total)
                    </label>
                    <div className="text-2xl font-bold font-mono text-emerald-400">
                        {formatNum(snRequiredTotal, 2)}
                    </div>
                    {snRequiredTotal > 0 && Math.abs(snRequiredTotal - snSeed) > 0.05 && (
                        <div className="absolute right-4 top-1/2 -translate-y-1/2">
                             <button 
                                onClick={() => setSnSeed(Number(snRequiredTotal.toFixed(2)))}
                                title="Sincronizar: Usar SN Requerido como Semilla"
                                className="w-10 h-10 rounded-full bg-blue-600 hover:bg-blue-500 text-white flex items-center justify-center transition-all active:scale-95 shadow-lg shadow-blue-900/50"
                            >
                                <i className="fas fa-sync-alt"></i>
                            </button>
                        </div>
                    )}
                </div>
            </div>
             <p className="text-xs text-slate-500 mt-2 leading-relaxed">
                El diseño converge cuando <strong>SN Semilla ≈ SN Requerido</strong>.
            </p>
        </div>

        {/* Pavement Structure Visualizer */}
        <div className="col-span-1 md:col-span-2 bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-lg">
            <h2 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <i className="fas fa-layer-group text-purple-500"></i> Estructura de Pavimento Requerida
            </h2>

            <div className="flex flex-col relative pl-4">
                {/* Headers */}
