import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { VEHICLE_NAMES, DEFAULT_COMPOSITION } from '../constants';
import { CompositionData } from '../types';

const COMMON_VEHICLES = ["A2", "B2", "C2", "C38", "T3S2", "T3S3", "T3S2R4"];

const CompositionPage: React.FC = () => {
  const navigate = useNavigate();
  const [values, setValues] = useState<CompositionData>(DEFAULT_COMPOSITION);

  // Load initial data
  useEffect(() => {
    const saved = localStorage.getItem('compVehData');
    if (saved) {
      try {
        setValues(JSON.parse(saved));
      } catch (e) {
        console.error("Error loading composition data", e);
      }
    }
  }, []);

  // Calculate sum automatically
  const total = useMemo(() => {
    return values.reduce((acc, curr) => acc + (Number(curr) || 0), 0);
  }, [values]);

  const isValid = Math.abs(total - 100.0) < 0.01;

  const handleInputChange = (index: number, valStr: string) => {
    const newVal = parseFloat(valStr);
    const newValues = [...values];
    newValues[index] = isNaN(newVal) ? 0 : newVal;
    setValues(newValues);
  };

  const handleSave = () => {
    if (!isValid) {
      alert("La sumatoria debe ser exactamente 100.00% para continuar.");
      return;
    }
    localStorage.setItem('compVehData', JSON.stringify(values));
    navigate('/ejes');
  };

  const handleReset = () => {
    if(window.confirm("¿Restablecer a los valores por defecto?")) {
        setValues(DEFAULT_COMPOSITION);
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 pb-32">
      <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
            <h1 className="text-3xl font-bold text-white mb-2">Composición Vehicular</h1>
            <p className="text-slate-400">Ingrese el porcentaje (%) para cada tipo de vehículo según NOM-012.</p>
        </div>

        <div className="flex items-center gap-4">
            <button 
                onClick={handleReset}
                className="px-4 py-2 text-sm text-slate-400 hover:text-white border border-slate-700 hover:bg-slate-800 rounded transition-colors"
                title="Restablecer valores por defecto"
            >
                <i className="fas fa-undo mr-2"></i> Restablecer
            </button>

            {/* Sticky Total Indicator */}
            <div className={`
                px-6 py-3 rounded-lg font-mono text-xl font-bold border flex items-center gap-3 shadow-lg
                ${isValid 
                    ? 'bg-emerald-900/40 border-emerald-500 text-emerald-400' 
                    : 'bg-red-900/40 border-red-500 text-red-400'}
            `}>
                <span>Total:</span>
                <span>{total.toFixed(2)}%</span>
                {isValid ? <i className="fas fa-check"></i> : <i className="fas fa-exclamation-triangle"></i>}
            </div>
        </div>
      </header>

      <div className="mb-4 text-xs text-slate-500 flex items-center gap-2">
         <span className="w-3 h-3 bg-blue-500 rounded-sm inline-block"></span> Vehículos Comunes (Datos Viales)
         <span className="w-3 h-3 bg-slate-800 border border-slate-700 rounded-sm inline-block ml-4"></span> Vehículos Atípicos
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {VEHICLE_NAMES.map((name, index) => {
            const isCommon = COMMON_VEHICLES.includes(name);

            return (
                <div 
                    key={name} 
                    className={`
                        relative border rounded-lg p-4 flex items-center gap-4 transition-all duration-200
                        ${isCommon 
                            ? 'bg-slate-800 border-blue-500 shadow-lg shadow-blue-900/20 z-10' 
                            : 'bg-slate-900/60 border-slate-800 opacity-90 hover:opacity-100 hover:border-slate-600 hover:bg-slate-800'
                        }
                    `}
                >
                    {/* Common Indicator Badge */}
                    {isCommon && (
                        <div className="absolute top-0 right-0">
                             <div className="bg-blue-600 text-white text-[10px] font-bold px-2 py-0.5 rounded-bl-lg rounded-tr-md shadow-sm">
                                COMÚN
                             </div>
                        </div>
                    )}

                    <div className={`
                        w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm shrink-0
                        ${isCommon ? 'bg-blue-900/50 text-blue-200' : 'bg-slate-800 text-slate-500'}
                    `}>
                        {index + 1}
                    </div>

                    <div className={`
                        w-16 h-10 rounded border flex items-center justify-center shrink-0
                        ${isCommon 
                            ? 'bg-slate-900 border-blue-500/50 shadow-inner' 
                            : 'bg-slate-950 border-slate-700'}
                    `}>
                       <span className={`text-xs font-bold ${isCommon ? 'text-blue-400' : 'text-slate-500'}`}>
                            {name}
                       </span>
                    </div>

                    <div className="flex-grow">
                        <label className={`block text-xs mb-1 ${isCommon ? 'text-blue-300 font-semibold' : 'text-slate-500'}`}>
                            {name}
                        </label>
                        <div className="relative">
                            <input
                                type="number"
                                step="0.01"
                                value={values[index]}
                                onFocus={(e) => e.target.select()}
                                onChange={(e) => handleInputChange(index, e.target.value)}
                                className={`
                                    w-full rounded px-2 py-1 text-right focus:outline-none focus:ring-1 font-mono
                                    ${isCommon 
                                        ? 'bg-slate-900 border border-blue-500/50 text-white focus:border-blue-400 focus:ring-blue-400' 
                                        : 'bg-slate-950 border border-slate-700 text-slate-400 focus:border-slate-500 focus:ring-slate-500 focus:text-white'}
                                `}
                            />
                            <span className="absolute right-8 top-1.5 text-slate-500 text-xs pointer-events-none">%</span>
                        </div>
                    </div>
                </div>
            );
        })}
      </div>

      {/* Floating Action Bar */}
      <div className="fixed bottom-0 left-0 right-0 bg-slate-900/90 backdrop-blur-md border-t border-slate-800 p-4 z-40">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
            <div className="hidden sm:block text-slate-400 text-sm">
                {isValid 
                    ? "La composición es válida. Puede continuar." 
                    : `Faltan ${(100 - total).toFixed(2)}% para completar el 100%.`}
            </div>
            <button 
                onClick={handleSave}
                disabled={!isValid}
                className={`
                    px-8 py-3 rounded-lg font-bold shadow-lg flex items-center gap-2 transition-all
                    ${isValid 
                        ? 'bg-blue-600 hover:bg-blue-500 text-white hover:shadow-blue-500/25 cursor-pointer' 
                        : 'bg-slate-700 text-slate-500 cursor-not-allowed'}
                `}
            >
                <i className="fas fa-save"></i>
                Guardar y Calcular Ejes
            </button>
        </div>
      </div>
    </div>
  );
};

export default CompositionPage;

{
  "name": "Diseño de pavimentos flexibles AASHTO-93",
  "description": "Herramienta de ingeniería civil para la conversión de composición vehicular a ejes equivalentes según NOM-012-SCT-2-2017.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useMemo } from 'react';
import { GeneralData, CompositionData } from '../types';
import { DEFAULT_COMPOSITION, DEFAULT_GENERAL_DATA, TABLE_STATIC_ROWS, VEHICLE_NAMES } from '../constants';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface EsalRow {
  no: number;
  tipo: string;
  l2: number;
  lxKip: number;
  ejesAnio: number;
  fx: number;
  esalAnio: number;
}

// Approximation of Inverse Standard Normal Distribution (Probit)
function inverseNormalCDF(p: number): number {
    if (p <= 0 || p >= 1) return 0;
    const t = Math.sqrt(-2 * Math.log(p < 0.5 ? p : 1 - p));
    const c0 = 2.515517;
    const c1 = 0.802853;
    const c2 = 0.010328;
    const d1 = 1.432788;
    const d2 = 0.189269;
    const d3 = 0.001308;

    const x = t - ((c2 * t + c1) * t + c0) / (((d3 * t + d2) * t + d1) * t + 1);
    return p < 0.5 ? -x : x;
}

// Helper for Mobile Abbreviations
const getMobileLayerName = (name: string) => {
    switch (name) {
        case "Carpeta asfáltica alto desempeño": return "AD";
        case "Carpeta asfáltica normal": return "CA";
        case "Base asfáltica": return "BA";
        case "Base Cementada": return "BC";
        case "Base hidráulica": return "BH";
        case "Sub-Base Hidráulica": return "SB";
        default: return name.substring(0, 4); // Fallback
    }
};

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design (Restored Manual Input)
  const [snSeed, setSnSeed] = useState<number>(2.0); 

  // Store user-defined real thicknesses (keyed by layer ID)
  const [manualThicknesses, setManualThicknesses] = useState<Record<string, number>>({});

  // Feedback state
  const [isSaved, setIsSaved] = useState(false);

  // Data from previous steps
  const [genData, setGenData] = useState<GeneralData>(DEFAULT_GENERAL_DATA);
  const [compData, setCompData] = useState<CompositionData>(DEFAULT_COMPOSITION);

  useEffect(() => {
    // Load general inputs
    const savedGen = localStorage.getItem('datosGeneralesData');
    if (savedGen) setGenData({ ...DEFAULT_GENERAL_DATA, ...JSON.parse(savedGen) });

    // Load composition
    const savedComp = localStorage.getItem('compVehData');
    if (savedComp) setCompData(JSON.parse(savedComp));

    // NEW: Load saved calculations specific to this page
    const savedEsals = localStorage.getItem('esalsData');
    if (savedEsals) {
        try {
            const parsed = JSON.parse(savedEsals);
            if (parsed.snSeed !== undefined) setSnSeed(parsed.snSeed);
            if (parsed.manualThicknesses) setManualThicknesses(parsed.manualThicknesses);
        } catch (e) {
            console.error("Error loading saved esals data", e);
        }
    }
  }, []);

  const handleSaveCalculations = () => {
      const dataToSave = {
          snSeed,
          manualThicknesses
      };
      localStorage.setItem('esalsData', JSON.stringify(dataToSave));
      setIsSaved(true);
      setTimeout(() => setIsSaved(false), 3000);
  };

  // --- 1. RECALCULATE EJES ---
  const ejesResults = useMemo(() => {
    const compObj: Record<string, number> = {};
    VEHICLE_NAMES.forEach((name, idx) => {
        compObj[name] = compData[idx] || 0;
    });
    const getVal = (key: string) => compObj[key] || 0;

    const Pvc = genData.pvc;
    const TDPA = genData.tdpa;
    let fcp = 0.5;
    if (genData.lanes === '2') fcp = 0.45;
    if (genData.lanes === '3+') fcp = 0.4;
    const TDPAcd = fcp * TDPA;
    const fvp = 0.0365 * Pvc * TDPAcd;
    const fvv = 0.0365 * (100 - Pvc) * TDPAcd;

    const formulas = [
        () => 2 * getVal("A2") * (fvp + fvv),
        () => (100 - getVal("A2") + getVal("B4")) * fvp,
        () => (getVal("B2") + getVal("C2") + getVal("T2S1") + getVal("T2S2") + getVal("T2S3") + getVal("T2S2S2")) * fvp,
        () => (2*getVal("C2R2") + 2*getVal("C3R2") + getVal("C3R3") + getVal("C2R3") + 3*getVal("T2S1R2") + 2*getVal("T2S1R3") + 2*getVal("T2S2R2") + 3*getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + getVal("T3S2R3")) * fvp,
        () => (getVal("T2S1") + getVal("T3S1")) * fvp,
        () => (getVal("C2R2") + getVal("C2R3") + getVal("T2S1R2") + getVal("T2S1R3") + getVal("T2S2R2")) * fvp,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + 2*getVal("B4") + 2*getVal("C2") + getVal("C36") + getVal("C38") + 4*getVal("C2R2") + 3*getVal("C3R2") + 2*getVal("C3R3") + 3*getVal("C2R3") + 3*getVal("T2S1") + 2*getVal("T2S2") + getVal("T3S2") + getVal("T3S3") + 2*getVal("T3S1") + 5*getVal("T2S1R2") + 4*getVal("T2S1R3") + 4*getVal("T2S2R2") + 4*getVal("T3S1R2") + 3*getVal("T3S1R3") + 3*getVal("T3S2R2") + getVal("T3S2R4") + 2*getVal("T3S2R3") + getVal("T3S3S2") + 2*getVal("T2S2S2") + getVal("T3S2S2")) * fvv,
        () => (getVal("B2") + getVal("B36") + getVal("B38") + getVal("B4")) * fvv,
        () => (getVal("B36") + getVal("B4") + getVal("C36") + getVal("T3S1R3")) * fvp,
        () => (getVal("B38") + getVal("C38") + getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T3S2S2")) * fvp,
        () => (getVal("C3R3") + getVal("C2R3") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R3") + getVal("T3S2R2") + 3*getVal("T3S2R4") + 2*getVal("T3S2R3") + 2*getVal("T2S2S2") + 2*getVal("T3S2S2")) * fvp,
        () => (getVal("T2S2") + getVal("T3S2") + getVal("T3S3S2")) * fvp,
        () => (getVal("C3R2") + getVal("C3R3") + getVal("T3S1R2") + getVal("T3S2R2") + getVal("T3S2R4") + getVal("T3S2R3") + getVal("T3S3S2")) * fvp,
        () => (getVal("C36") + getVal("C38") + getVal("C3R2") + 2*getVal("C3R3") + getVal("C2R3") + getVal("T2S2") + 2*getVal("T3S2") + getVal("T3S3") + getVal("T3S1") + getVal("T2S1R3") + getVal("T2S2R2") + getVal("T3S1R2") + 2*getVal("T3S1R3") + 2*getVal("T3S2R2") + 4*getVal("T3S2R4") + 3*getVal("T3S2R3") + 2*getVal("T3S3S2") + 2*getVal("T2S2S2") + 3*getVal("T3S2S2")) * fvv,
        () => getVal("T3S3S2") * fvp,
        () => (getVal("T3S3") + getVal("T2S3")) * fvp,
        () => getVal("T3S3S2") * fvv
    ];

    return TABLE_STATIC_ROWS.map((row, i) => formulas[i] ? formulas[i]() : 0);
  }, [genData.pvc, genData.tdpa, genData.lanes, compData]);


  // --- 2. CALCULATE ESALS (Using Manual SN Seed for Fx) ---
  const { esalRows, growthFactor } = useMemo(() => {
    // We use the user's manual snSeed for the LEF conversion
    const log10 = Math.log10;
    const pow = Math.pow;

    // Gt
    const pt = genData.finalServiceability;
    const Gt = log10((4.2 - pt) / 2.7);

    // Beta 18
    const beta18 = 0.4 + (1094 / pow(snSeed + 1, 5.19));

    // Growth Factor
    const r = genData.growthRate / 100;
    const n = genData.designPeriod;
    let gf = n; 
    if (r !== 0) {
        gf = (pow(1 + r, n) - 1) / r;
    }

    const rows = TABLE_STATIC_ROWS.map((staticRow, index) => {
        const rowNo = staticRow[0];
        const rowTipo = staticRow[1];

        let l2 = 1;
        if (rowTipo === "Tándem") l2 = 2;
        if (rowTipo === "Trídem") l2 = 3;

        let weightTon = 0;
        switch(genData.roadType) {
            case 'ET_A': weightTon = staticRow[4]; break;
            case 'B':    weightTon = staticRow[5]; break;
            case 'C':    weightTon = staticRow[6]; break;
            case 'D':    weightTon = staticRow[7]; break;
            default:     weightTon = staticRow[4];
        }
        const lxKip = weightTon * 2.20462; 

        // Beta X
        const numeratorBx = 0.081 * pow(lxKip + l2, 3.23);
        const denominatorBx = pow(snSeed + 1, 5.19) * pow(l2, 3.23);
        const betaX = 0.4 + (numeratorBx / denominatorBx);

        // Fx Exponent
        const term1 = 4.79 * log10(18 + 1); 
        const term2 = 4.79 * log10(lxKip + l2);
        const term3 = 4.33 * log10(l2);
        const term4 = Gt / betaX;
        const term5 = Gt / beta18;

        const exponent = term1 - term2 + term3 + term4 - term5;
        const fx = 1 / pow(10, exponent);

        const ejes = ejesResults[index] || 0;
        const esal = fx * ejes;

        return {
            no: rowNo,
            tipo: rowTipo,
            l2,
            lxKip,
            ejesAnio: ejes,
            fx,
            esalAnio: esal
        };
    });

    return { esalRows: rows, growthFactor: gf };
  }, [snSeed, genData.finalServiceability, genData.roadType, genData.growthRate, genData.designPeriod, ejesResults]);

  const totalESALs1Year = useMemo(() => esalRows.reduce((acc, r) => acc + r.esalAnio, 0), [esalRows]);
  const totalESALsDesign = totalESALs1Year * growthFactor;


  // --- 3. HELPER: Automatic Iterative SN Calculation (FOR STRUCTURE LAYERS) ---
  const solveAashtoIterative = (Mr: number, W18: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;

    const log10 = Math.log10;
    const pow = Math.pow;
    const abs = Math.abs;

    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt; 

    const logW18 = log10(W18);
    const zrSo = Zr * So;
    const logMrTerm = 2.32 * log10(Mr);
    const psiTerm = log10(dPSI / 2.7); 

    let currentSeed = 2.0; 
    let snReq = 0;
    let error = 1.0;
    let iterations = 0;
    const maxIterations = 100;

    while (error > 0.001 && iterations < maxIterations) {
        iterations++;
        const denominator = 0.4 + (1094 / pow(currentSeed + 1, 5.19));
        const fraction = psiTerm / denominator;
        const beta = logW18 - zrSo - fraction - logMrTerm + 8.27;
        snReq = -1 + pow(10, beta / 9.36);
        error = abs(snReq - currentSeed);
        if (error >= 0.001) currentSeed = snReq;
    }

    return snReq > 0 ? snReq : 0;
  };

  // --- 4. HELPER: Manual Calculation (FOR TOP CARD) ---
  const calculateManualSN = (Mr: number, W18: number, seed: number): number => {
    if (W18 <= 0 || Mr <= 0) return 0;
    const log10 = Math.log10;
    const pow = Math.pow;

    const p = 1 - (genData.reliability / 100);
    const Zr = inverseNormalCDF(p);
    const So = genData.standardDeviation;
    const Pt = genData.finalServiceability;
    const dPSI = 4.2 - Pt;

    const logW18 = log10(W18);
    const zrSo = Zr * So;
    const logMrTerm = 2.32 * log10(Mr);
    const psiTerm = log10(dPSI / 2.7);

    // Uses the Manual Seed
    const denominator = 0.4 + (1094 / pow(seed + 1, 5.19));
    const fraction = psiTerm / denominator;

    const beta = logW18 - zrSo - fraction - logMrTerm + 8.27;
    const snReq = -1 + pow(10, beta / 9.36);
    return snReq > 0 ? snReq : 0;
  };

  // The Top Card uses the Manual Calculation
  const snRequiredTotalManual = useMemo(() => {
    return calculateManualSN(genData.subgradeMr, totalESALsDesign, snSeed);
  }, [totalESALsDesign, genData, snSeed]);


  // --- 5. LAYER STRUCTURE CALCULATION (Uses Automatic Iteration) ---
  const structureLayers = useMemo(() => {
      let accumulatedSN = 0;

      return genData.layers.map((layer, index) => {
          // Identify Supporting Layer Mr
          const isLast = index === genData.layers.length - 1;
          const supportMr = isLast ? genData.subgradeMr : genData.layers[index + 1].mr;

          // SN Required is calculated AUTOMATICALLY (Iteratively) for each layer
          const snRequiredForSupport = solveAashtoIterative(supportMr, totalESALsDesign);

          // Net SN needed from THIS layer
          let snNeededFromLayer = Math.max(0, snRequiredForSupport - accumulatedSN);

          const asphaltLayerNames = [
              "Carpeta asfáltica alto desempeño", 
              "Carpeta asfáltica normal", 
              "Base asfáltica"
          ];
          const m = asphaltLayerNames.includes(layer.name) ? 1.0 : (genData.drainageCoefficient || 1.0);

          const h_in_calc = snNeededFromLayer / (layer.a * m);
          const h_cm_calc = h_in_calc * 2.54;

          const manualVal = manualThicknesses[layer.id];
          const h_cm_real = manualVal !== undefined ? manualVal : Math.ceil(h_cm_calc * 2) / 2;

          const snProvided = (h_cm_real / 2.54) * layer.a * m;
          accumulatedSN += snProvided; 

          return {
              ...layer,
              supportMr,
              snReq: snRequiredForSupport,
              m,
              h_in_calc,
              h_cm_calc,
              h_cm_real,
              snProvided
          };
      });
  }, [genData.layers, genData.subgradeMr, genData.drainageCoefficient, totalESALsDesign, manualThicknesses]);

  const handleRealThicknessChange = (layerId: string, val: string) => {
      const num = parseFloat(val);
      setManualThicknesses(prev => ({
          ...prev,
          [layerId]: isNaN(num) ? 0 : num
      }));
  };

  const formatNum = (n: number, d: number = 2) => n.toLocaleString('en-US', { minimumFractionDigits: d, maximumFractionDigits: d });

  const generatePDF = () => {
    const doc = new jsPDF();

    // --- Header ---
    doc.setFontSize(18);
    doc.text("Memoria de Cálculo - Diseño de Pavimento", 14, 20);

    doc.setFontSize(10);
    doc.text(`Proyecto: ${genData.projectName}`, 14, 30);
    doc.text(`Tramo: ${genData.section}`, 14, 35);
    doc.text(`Fecha: ${new Date().toLocaleDateString()}`, 14, 40);

    // --- 1. Datos Generales ---
    doc.setFontSize(14);
    doc.text("1. Datos de Diseño", 14, 50);

    const datosBody = [
        ["TDPA", genData.tdpa, "Confiabilidad (R)", `${genData.reliability}%`],
        ["Porcentaje de vehículos cargados", `${genData.pvc}%`, "Desviación (So)", genData.standardDeviation],
        ["Tasa Crecimiento", `${genData.growthRate}%`, "Serviciabilidad final (Pt)", genData.finalServiceability],
        ["Periodo Diseño", `${genData.designPeriod} años`, "Módulo Subrasante", `${formatNum(genData.subgradeMr, 0)} psi`],
        ["Carriles", genData.lanes, "Tipo Camino", genData.roadType],
    ];

    autoTable(doc, {
        startY: 55,
        head: [['Parámetro', 'Valor', 'Parámetro', 'Valor']],
        body: datosBody,
        theme: 'grid',
        headStyles: { fillColor: [41, 128, 185] },
    });

    // --- 2. Composición Vehicular (Resumida) ---
    const compRows = VEHICLE_NAMES.map((name, i) => ({ name, val: compData[i] || 0 }))
                                  .filter(item => item.val > 0)
                                  .map(item => [item.name, `${item.val}%`]);

    let finalY = (doc as any).lastAutoTable.finalY || 60;

    doc.setFontSize(14);
    doc.text("2. Composición Vehicular ( > 0% )", 14, finalY + 10);

    autoTable(doc, {
        startY: finalY + 15,
        head: [['Vehículo', '%', 'Vehículo', '%']],
        body: (() => {
            const rows = [];
            for (let i = 0; i < compRows.length; i += 2) {
                const row = [
                    compRows[i][0], compRows[i][1],
                    compRows[i+1] ? compRows[i+1][0] : '', compRows[i+1] ? compRows[i+1][1] : ''
                ];
                rows.push(row);
            }
            return rows;
        })(),
        theme: 'grid',
        styles: { fontSize: 8 },
        headStyles: { fillColor: [52, 73, 94] }
    });

    finalY = (doc as any).lastAutoTable.finalY || 100;

    // --- 3. Resultados de Ejes y ESALs ---
    doc.setFontSize(14);
    doc.text("3. Cálculo de Ejes Equivalentes (ESALs)", 14, finalY + 10);

    doc.setFontSize(10);
    doc.text(`Total ESALs de Diseño: ${formatNum(totalESALsDesign, 0)}`, 14, finalY + 18);

    const filteredEsalRows = esalRows.filter(r => r.ejesAnio > 0);

    autoTable(doc, {
        startY: finalY + 22,
        head: [['No', 'Tipo', 'L2', 'Lx(kip)', 'Ejes/Año', 'Fx', 'ESAL Diseño']],
        body: filteredEsalRows.map(r => [
            r.no, r.tipo, r.l2, r.lxKip.toFixed(2), 
            Math.round(r.ejesAnio).toLocaleString(),
            r.fx.toFixed(4),
            (r.esalAnio * growthFactor).toLocaleString(undefined, {maximumFractionDigits: 0})
        ]),
        theme: 'grid',
        styles: { fontSize: 7 },
        headStyles: { fillColor: [46, 204, 113], textColor: 255 }
    });

    finalY = (doc as any).lastAutoTable.finalY || 150;

    if (finalY > 240) {
        doc.addPage();
        finalY = 20;
    }

    // --- 4. Diseño Estructural ---
    const totalSnReal = structureLayers.reduce((acc, layer) => acc + (layer.snProvided || 0), 0);

    doc.setFontSize(14);
    doc.text("4. Estructura de Pavimento Requerida", 14, finalY + 10);
    doc.setFontSize(10);

    doc.text(`SN Requerido (Subrasante): ${formatNum(snRequiredTotalManual, 2)} (Manual)`, 14, finalY + 18);

    const snRealText = `SN Real Total: ${formatNum(totalSnReal, 2)}`;
    const pageWidth = doc.internal.pageSize.getWidth();
    const textWidth = doc.getTextWidth(snRealText);
    doc.text(snRealText, pageWidth - 14 - textWidth, finalY + 18);

    autoTable(doc, {
        startY: finalY + 22,
        head: [['Capa', 'Aporte (a)', 'Dren (m)', 'E (psi)', 'SN Req', 'h calc (cm)', 'h REAL (cm)']],
        body: structureLayers.map(l => [
            l.name,
            l.a,
            l.m,
            formatNum(l.mr, 0),
            formatNum(l.snReq, 2),
