// Approximation of Inverse Standard Normal Distribution (Probit)
function inverseNormalCDF(p: number): number {
    if (p <= 0 || p >= 1) return 0;
    const t = Math.sqrt(-2 * Math.log(p < 0.5 ? p : 1 - p));
    const c0 = 2.515517;
    const c1 = 0.802853;
    const c2 = 0.010328;
    const d1 = 1.432788;
    const d2 = 0.189269;
    const d3 = 0.001308;

    const x = t - ((c2 * t + c1) * t + c0) / (((d3 * t + d2) * t + d1) * t + 1);
    return p < 0.5 ? -x : x;
}

// Helper for Mobile Abbreviations
const getMobileLayerName = (layer: PavementLayer) => {
    // If it's a custom user layer, use the user provided code
    if (layer.customCode) return layer.customCode;

    switch (layer.name) {
        case "Carpeta asfáltica alto desempeño": return "AD";
        case "Carpeta asfáltica normal": return "CA";
        case "Base asfáltica": return "BA";
        case "Base Cementada": return "BC";
        case "Base hidráulica": return "BH";
        case "Sub-Base Hidráulica": return "SB";
        default: return layer.name.substring(0, 4); // Fallback
    }
};

const EsalsPage: React.FC = () => {
  // Inputs for AASHTO Design (Restored Manual Input)
  const [snSeed, setSnSeed] = useState<number>(2.0); 

